export const VideoIntro: React.FC<VideoIntroProps> = ({ onVideoEnd }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFadingOut, setIsFadingOut] = useState(false);
  const [isFinished, setIsFinished] = useState(false);

  useEffect(() => {
    // Sequence timing logic
    const intervalTime = 800; // Time per word
    const totalWords = SUFFIXES.length;

    const interval = setInterval(() => {
      setCurrentIndex((prev) => {
        if (prev >= totalWords - 1) {
          clearInterval(interval);

          // Trigger exit sequence after landing on "de"
          setTimeout(() => {
            setIsFinished(true); // Stop cursor blinking or lock state
            setTimeout(() => {
              setIsFadingOut(true); // Start fade out
              setTimeout(() => {
                onVideoEnd(); // Unmount from App
              }, 800); // Wait for fade out CSS transition
            }, 1200); // Hold the final "rangga.de" for a moment
          }, 100);

          return prev;
        }
        return prev + 1;
      });
    }, intervalTime);

    return () => clearInterval(interval);
  }, [onVideoEnd]);

  return (
    <>
      <style>{`
        @keyframes blink {
          0%, 100% { opacity: 1; }
          50% { opacity: 0; }
        }
        .intro-blur-enter {
          filter: blur(0px);
          transform: translateY(0);
          opacity: 1;
        }
        .intro-blur-exit {
          filter: blur(10px);
          transform: translateY(20px);
          opacity: 0;
        }
      `}</style>

      <div style={{ ...styles.container, opacity: isFadingOut ? 0 : 1 }}>
        <div style={styles.gridBackground} />

        <div style={styles.contentWrapper}>
          <span style={styles.staticText}>rangga.</span>

          <div style={styles.dynamicWrapper}>
             {/* We create a visual carousel by rendering the current text */}
             {SUFFIXES.map((suffix, index) => {
               // Calculate position relative to current index
               let className = 'intro-blur-exit'; // Default hidden state

               if (index === currentIndex) {
                 className = 'intro-blur-enter'; // Current visible
               }

               // Only render the current, previous (for exit anim), and next (for smooth entry if needed)
               if (index !== currentIndex) return null;

               return (
                 <span key={suffix} style={styles.dynamicText} className={className}>
                   {suffix}
                 </span>
               );
             })}

             {/* Invisible spacer to maintain width of the container based on longest word */}
             <span style={{ opacity: 0, pointerEvents: 'none', fontSize: styles.dynamicText.fontSize, fontWeight: 700 }}>
               develop
             </span>
          </div>

          <div style={{ 
            ...styles.cursor, 
            opacity: isFadingOut ? 0 : 1,
            animation: isFinished ? 'none' : 'blink 1s step-end infinite',
            backgroundColor: isFinished ? 'transparent' : 'var(--primary-color)' 
          }} />
        </div>
      </div>
    </>
  );
};

