export const VideoIntro: React.FC<VideoIntroProps> = ({ onVideoEnd }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFadingOut, setIsFadingOut] = useState(false);
  const [isFinished, setIsFinished] = useState(false);

  useEffect(() => {
    // Timing Logic: Cepat di awal, melambat di akhir untuk penekanan
    const wordDuration = 700; 
    const finalHoldDuration = 1800; // Tahan lama di "rangga.de"
    const totalWords = SEQUENCE.length;

    const interval = setInterval(() => {
      setCurrentIndex((prev) => {
        if (prev >= totalWords - 1) {
          clearInterval(interval);

          // Sequence akhir
          setTimeout(() => {
            setIsFinished(true); // Stop cursor blink, lock state

            setTimeout(() => {
              setIsFadingOut(true); // Trigger fade out CSS

              setTimeout(() => {
                onVideoEnd(); // Unmount component
              }, 1500); // Wait for CSS opacity transition to finish

            }, finalHoldDuration); 
          }, 50);

          return prev;
        }
        return prev + 1;
      });
    }, wordDuration);

    return () => clearInterval(interval);
  }, [onVideoEnd]);

  const currentConfig = SEQUENCE[currentIndex];

  return (
    <>
      <style>{`
        @keyframes blink {
          0%, 100% { opacity: 1; transform: scaleY(1); }
          50% { opacity: 0.2; transform: scaleY(0.8); }
        }

        .fluid-text-enter {
          animation: cinematicGlitchIn 0.6s cubic-bezier(0.22, 1, 0.36, 1) forwards;
        }

        @keyframes cinematicGlitchIn {
          0% {
            opacity: 0;
            filter: blur(15px);
            transform: translateY(30px) skewX(-25deg) scale(1.1);
          }
          40% {
             filter: blur(5px);
             transform: translateY(-8px) skewX(10deg) scale(0.95);
          }
          70% {
             filter: blur(1px);
             transform: translateY(3px) skewX(-5deg);
          }
          100% {
            opacity: 1;
            filter: blur(0);
            transform: translateY(0) skewX(0) scale(1);
          }
        }
      `}</style>

      <div style={{ ...styles.container, opacity: isFadingOut ? 0 : 1 }}>
        <div style={styles.gridBackground} />

        <div style={styles.contentWrapper}>
          <span style={styles.staticText}>rangga.</span>

          <div style={styles.dynamicWrapper}>
             {SEQUENCE.map((item, index) => {
               // Only render the current word to keep DOM light
               if (index !== currentIndex) return null;

               const itemStyle: React.CSSProperties = {
                   ...styles.dynamicTextBase,
                   color: item.color,
                   fontFamily: item.fontFamily || 'inherit',
                   fontWeight: item.fontWeight || 700,
                   letterSpacing: item.letterSpacing || 'normal',
                   fontStyle: item.fontStyle || 'normal',
                   textShadow: item.textShadow || 'none',
               };

               return (
                 <span key={item.text} style={itemStyle} className="fluid-text-enter">
                   {item.text}
                 </span>
               );
             })}

             {/* Invisible spacer to maintain layout height/width stability */}
             <span style={{ 
               opacity: 0, 
               pointerEvents: 'none', 
               fontSize: styles.dynamicTextBase.fontSize, 
               fontFamily: "'Courier New', monospace", 
               fontWeight: 700 
             }}>
               develop_
             </span>
          </div>

          <div style={{ 
            ...styles.cursor, 
            backgroundColor: currentConfig.color, // Warna kursor mengikuti kata
            color: currentConfig.color, // Untuk box-shadow currentColor
            opacity: isFadingOut ? 0 : 1,
            animation: isFinished ? 'none' : 'blink 0.9s step-end infinite',
            // Sembunyikan kursor saat selesai agar fokus penuh pada logo final
            display: isFinished ? 'none' : 'inline-block' 
          }} />
        </div>
      </div>
    </>
  );
};

