export const VideoIntro: React.FC<VideoIntroProps> = ({ onVideoEnd }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFadingOut, setIsFadingOut] = useState(false);
  const [showCursor, setShowCursor] = useState(true);

  // Audio Refs
  const audioCtxRef = useRef<AudioContext | null>(null);

  // --- AUDIO ENGINE ---
  const playSound = useCallback((freq = 200, type: OscillatorType = 'sine', duration = 0.1) => {
    try {
        if (!audioCtxRef.current) {
             const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
             audioCtxRef.current = new AudioContextClass();
        }
        const ctx = audioCtxRef.current;

        // Safety check if context is suspended (browser policy)
        if (ctx.state === 'suspended') {
            ctx.resume().catch(() => {}); 
        }

        const osc = ctx.createOscillator();
        const gain = ctx.createGain();

        osc.type = type;
        osc.frequency.setValueAtTime(freq, ctx.currentTime);

        gain.gain.setValueAtTime(0.1, ctx.currentTime);
        gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + duration);

        osc.connect(gain);
        gain.connect(ctx.destination);

        osc.start();
        osc.stop(ctx.currentTime + duration);
    } catch (e) {
        // Silent fail for audio to prevent crash
    }
  }, []);

  // --- FINISH SEQUENCE ---
  const finishSequence = useCallback(() => {
    setIsFadingOut(true);
    // Safety delay to ensure animation finishes before unmounting
    setTimeout(() => {
      onVideoEnd(); 
    }, 800); // Match transition duration
  }, [onVideoEnd]);

  // --- SEQUENCE LOGIC ---
  useEffect(() => {
    let timeout: NodeJS.Timeout;

    // Determine duration based on index (speed up in middle, slow down at end)
    const isLast = currentIndex === SUFFIX_SEQUENCE.length - 1;
    const duration = isLast ? 2000 : (currentIndex === 0 ? 800 : 150); // Fast middle, hold end

    // Play Sound
    if (!isFadingOut) {
        if (isLast) {
            playSound(110, 'triangle', 0.5); // "Ta-da" low sound
            playSound(220, 'sine', 0.5); 
        } else {
            playSound(400 + (Math.random() * 200), 'sawtooth', 0.05); // Glitch/Type sound
        }
    }

    timeout = setTimeout(() => {
      if (isLast) {
        setShowCursor(false); // Hide cursor at the very end
        finishSequence();
      } else {
        setCurrentIndex(prev => prev + 1);
      }
    }, duration);

    return () => clearTimeout(timeout);
  }, [currentIndex, finishSequence, playSound, isFadingOut]);


  const currentSuffix = SUFFIX_SEQUENCE[currentIndex];

  return (
    <>
      <style>{`
        @keyframes blink { 0%, 100% { opacity: 1; } 50% { opacity: 0; } }

        .glitch-text {
          position: relative;
        }
        .glitch-text::before,
        .glitch-text::after {
          content: attr(data-text);
          position: absolute;
          top: 0;
          left: 0;
          width: 100%;
          height: 100%;
          background: #050810;
        }
        .glitch-text::before {
          left: 2px;
          text-shadow: -1px 0 #ff00c1;
          clip: rect(44px, 450px, 56px, 0);
          animation: glitch-anim 5s infinite linear alternate-reverse;
        }
        .glitch-text::after {
          left: -2px;
          text-shadow: -1px 0 #00fff9;
          clip: rect(44px, 450px, 56px, 0);
          animation: glitch-anim2 5s infinite linear alternate-reverse;
        }
        @keyframes glitch-anim {
          0% { clip: rect(10px, 9999px, 30px, 0); transform: skew(0.5deg); }
          5% { clip: rect(70px, 9999px, 90px, 0); transform: skew(0.1deg); }
          100% { clip: rect(10px, 9999px, 100px, 0); transform: skew(0); }
        }
        @keyframes glitch-anim2 {
          0% { clip: rect(60px, 9999px, 80px, 0); transform: skew(0.5deg); }
          5% { clip: rect(20px, 9999px, 40px, 0); transform: skew(0.1deg); }
          100% { clip: rect(50px, 9999px, 90px, 0); transform: skew(0); }
        }
      `}</style>

      <div style={{ ...styles.container, opacity: isFadingOut ? 0 : 1, pointerEvents: isFadingOut ? 'none' : 'auto' }}>
        <div style={styles.gridBackground} />

        <div style={styles.textWrapper}>
          <span style={styles.staticText}>rangga.</span>
          <span 
            style={{ 
                ...styles.dynamicText, 
                color: currentSuffix.color, 
                fontFamily: currentSuffix.fontFamily || 'inherit'
            }}
            className={currentSuffix.isGlitch ? 'glitch-text' : ''}
            data-text={currentSuffix.text}
          >
            {currentSuffix.text}
          </span>
          {showCursor && (
            <span style={{ ...styles.cursor, color: currentSuffix.color }} />
          )}
        </div>

        <button style={styles.skipButton} onClick={finishSequence}>
            SKIP INTRO &gt;&gt;
        </button>
      </div>
    </>
  );
};

