export const VideoIntro: React.FC<VideoIntroProps> = ({ onVideoEnd }) => {
  const [stepIndex, setStepIndex] = useState(0);
  const [isFadingOut, setIsFadingOut] = useState(false);
  const audioCtxRef = useRef<AudioContext | null>(null);
  const timeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // --- Audio Engine (Procedural) ---
  const playSound = useCallback((freq: number, type: OscillatorType, length: number) => {
    try {
        if (!audioCtxRef.current) {
             const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
             audioCtxRef.current = new AudioContextClass();
        }
        const ctx = audioCtxRef.current;
        if (ctx.state === 'suspended') ctx.resume();

        const osc = ctx.createOscillator();
        const gain = ctx.createGain();

        osc.type = type;
        osc.frequency.setValueAtTime(freq, ctx.currentTime);

        gain.gain.setValueAtTime(0.05, ctx.currentTime);
        gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + length);

        osc.connect(gain);
        gain.connect(ctx.destination);

        osc.start();
        osc.stop(ctx.currentTime + length);
    } catch (e) {
        // Ignore audio errors
    }
  }, []);

  const finish = useCallback(() => {
    if (timeoutRef.current) clearTimeout(timeoutRef.current);
    setIsFadingOut(true);
    // Play final success sound
    playSound(440, 'sine', 0.1);
    playSound(880, 'sine', 0.4);

    // Allow fade out animation to complete before unmounting
    setTimeout(() => {
        onVideoEnd();
    }, 800);
  }, [onVideoEnd, playSound]);

  useEffect(() => {
    const currentStep = SEQUENCE[stepIndex];
    const isLast = stepIndex === SEQUENCE.length - 1;

    // Play glitch/type sound for each step
    if (!isLast && !isFadingOut) {
        const freq = 100 + (Math.random() * 200);
        playSound(freq, 'sawtooth', 0.05);
    }

    if (isLast) {
       // We reached "rangga.de"
       // Hold it for the duration specified in the last step (2000ms) then finish
       timeoutRef.current = setTimeout(finish, currentStep.speed);
    } else {
       // Move to next word
       timeoutRef.current = setTimeout(() => {
         setStepIndex(prev => prev + 1);
       }, currentStep.speed);
    }

    return () => {
        if (timeoutRef.current) clearTimeout(timeoutRef.current);
    };
  }, [stepIndex, finish, playSound, isFadingOut]);

  const currentStep = SEQUENCE[stepIndex];

  return (
    <>
      <style>{`
        @keyframes blink { 0%, 100% { opacity: 1; } 50% { opacity: 0; } }
        .intro-suffix {
            display: inline-block;
            animation: glitch-skew 0.3s cubic-bezier(0.25, 0.46, 0.45, 0.94) both infinite;
        }
        @keyframes glitch-skew {
            0% { transform: skew(0deg); }
            20% { transform: skew(-2deg); }
            40% { transform: skew(2deg); }
            60% { transform: skew(-1deg); }
            80% { transform: skew(1deg); }
            100% { transform: skew(0deg); }
        }
      `}</style>

      <div style={{ ...styles.container, opacity: isFadingOut ? 0 : 1, pointerEvents: isFadingOut ? 'none' : 'auto' }}>
        <div style={styles.gridBackground} />

        <div style={styles.contentWrapper}>
          {/* Static Part */}
          <span style={styles.staticText}>rangga.</span>

          {/* Bridge Part ("de") */}
          <span style={styles.bridgeText}>de</span>

          {/* Dynamic Suffix (starts empty, but conceptually we append "fine", "sign", etc) */}
          <span 
            className="intro-suffix"
            style={{ ...styles.dynamicSuffix, color: currentStep.color }}
          >
            {currentStep.text}
          </span>

          {/* Blinking Cursor */}
          <span style={styles.cursor} />
        </div>

        <button style={styles.skipButton} onClick={finish}>
            SKIP_INTRO &gt;&gt;
        </button>
      </div>
    </>
  );
};

import React, { useState, Suspense, useCallback, useEffect } from 'react';
import { useProgress } from '@react-three/drei';
import { Experience3D } from './components/Experience3D';
import { StartScreen } from './components/ui/StartScreen';
import { AudioProvider } from './contexts/AudioContext';
import { useAudio } from './hooks/useAudio';
import { VideoIntro } from './components/ui/VideoIntro';

const AppContent: React.FC = () => {
  const { progress } = useProgress();
  // State: video -> loading -> start (waiting for user) -> entering (animation) -> experience
  const [appState, setAppState] = useState<'video' | 'loading' | 'start' | 'entering' | 'experience'>('video');
  const audio = useAudio();

  // Threshold to switch from loading to start button
  const isLoaded = progress >= 100;

  const handleVideoEnd = useCallback(() => {
    setAppState('loading');
  }, []);

  useEffect(() => {
    if (appState === 'loading' && isLoaded) {
      // Small delay to ensure smooth transition from loader to button
      const timer = setTimeout(() => setAppState('start'), 800);
      return () => clearTimeout(timer);
    }
  }, [appState, isLoaded]);

  const handleStart = useCallback(() => {
    if (appState === 'start') {
      audio.play('confirm');
      audio.play('gate_open', { volume: 0.8 });

      // Start main ambience loop immediately
      audio.playLoop('ambience', { volume: 0.2 });
      audio.playLoop('flyby', { volume: 0.15 });

      setAppState('entering');
    }
  }, [appState, audio]);

  const handleIntroEnd = useCallback(() => {
    setAppState('experience');
  }, []);

  const showVideo = appState === 'video';

  // FIX: Render Experience3D as soon as video ends. 
  // It will be hidden behind the StartScreen, allowing it to "warm up" (compile shaders).
  // This prevents the black flash/blank screen when opening the doors.
  const showExperienceCanvas = appState !== 'video';

  // Keep StartScreen mounted during loading, start, and entering phases.
  const showStartScreen = appState === 'loading' || appState === 'start' || appState === 'entering';

  const isHudVisible = appState === 'experience';

  return (
    <>
      {showVideo && <VideoIntro onVideoEnd={handleVideoEnd} />}

      <main style={{ width: '100vw', height: '100vh', backgroundColor: '#050810' }}>
        <Suspense fallback={null}>
          {showExperienceCanvas && (
            <Experience3D 
              isHudVisible={isHudVisible} 
              isEntering={appState === 'entering'} 
            />
          )}
        </Suspense>
      </main>

      {showStartScreen && (
        <StartScreen
          appState={appState}
          progress={progress}
          onStart={handleStart}
          onIntroEnd={handleIntroEnd}
        />
      )}
    </>
  );
};

const App: React.FC = () => {
  return (
    <AudioProvider>
      <AppContent />
    </AudioProvider>
  );
};


export default App;

