import React, { useRef, useMemo } from 'react';
// FIX: Add side-effect import to ensure R3F's JSX types are globally available.
import '@react-three/fiber';
import { useFrame, useThree } from '@react-three/fiber';
import * as THREE from 'three';

const DataTrail: React.FC = () => {
  const count = 50;
  const mesh = useRef<THREE.InstancedMesh>(null!);
  const { camera, mouse } = useThree();

  const dummy = useMemo(() => new THREE.Object3D(), []);

  const particles = useMemo(() => {
    const temp = [];
    for (let i = 0; i < count; i++) {
      temp.push({
        position: new THREE.Vector3(),
        scale: 1,
        life: 0,
      });
    }
    return temp;
  }, [count]);

  // Use a stable Raycaster setup to find the mouse position in 3D space
  const raycaster = useMemo(() => new THREE.Raycaster(), []);
  const groundPlane = useMemo(() => new THREE.Plane(new THREE.Vector3(0, 1, 0), 0), []); // An invisible plane at y=0
  const intersectionPoint = useMemo(() => new THREE.Vector3(), []);

  useFrame((_state, delta) => {
    if (!mesh.current) return;

    // Update raycaster from the current mouse and camera position
    raycaster.setFromCamera(mouse, camera);

    // Find the precise point where the mouse ray intersects the invisible ground plane
    raycaster.ray.intersectPlane(groundPlane, intersectionPoint);

    const pos = intersectionPoint;

    particles.forEach((particle, i) => {
      if (particle.life <= 0) {
        // Respawn particle
        if (i === 0) { // Leader particle follows the mouse
            particle.position.copy(pos);
            particle.life = 1;
            particle.scale = Math.random() * 0.05 + 0.02;
        }
      } else {
        // Update particle life
        particle.life -= delta * 2;
        if (i > 0) {
            // Follow the particle in front
            const prev = particles[i - 1];
            particle.position.lerp(prev.position, delta * 15);
        }
      }

      dummy.position.copy(particle.position);
      dummy.scale.set(particle.scale * particle.life, particle.scale * particle.life, particle.scale * particle.life);
      dummy.updateMatrix();
      mesh.current.setMatrixAt(i, dummy.matrix);
    });

    mesh.current.instanceMatrix.needsUpdate = true;
  });

  return (
    <instancedMesh ref={mesh} args={[undefined, undefined, count]}>
      <sphereGeometry args={[0.2, 8, 8]} />
      <meshStandardMaterial color="#00ffff" emissive="#00ffff" toneMapped={false} transparent opacity={0.5} />
    </instancedMesh>
  );
};

export default DataTrail;

import React, { useState, useRef, useMemo } from 'react';
// FIX: Add side-effect import to ensure R3F's JSX types are globally available.
import '@react-three/fiber';
// FIX: Add useThree to provide types for JSX primitives
import { useFrame, ThreeEvent, useThree } from '@react-three/fiber';
import * as THREE from 'three';
import { CityDistrict } from '../../types';
import { Text } from '@react-three/drei';

interface DistrictBuildingProps {
  district: CityDistrict;
  onSelect?: (district: CityDistrict) => void;
  isSelected?: boolean;
  isUnlocked?: boolean;
}

const UNLOCKED_COLOR = new THREE.Color('#005577');
const HOVER_COLOR = new THREE.Color('#00aaff');
const SELECTED_COLOR = new THREE.Color('#00ffff');
const LOCKED_COLOR = new THREE.Color('#333333');

const DistrictBuilding: React.FC<DistrictBuildingProps> = ({
  district,
  onSelect,
  isSelected,
  isUnlocked = true,
}) => {
  // FIX: Call useThree to provide types for JSX primitives
  useThree();
  const meshRef = useRef<THREE.Mesh>(null!);
  const [isHovered, setIsHovered] = useState(false);

  const height = district.height || 20;

  const targetColor = useMemo(() => {
    if (!isUnlocked) return LOCKED_COLOR;
    if (isSelected) return SELECTED_COLOR;
    if (isHovered) return HOVER_COLOR;
    return UNLOCKED_COLOR;
  }, [isSelected, isHovered, isUnlocked]);

  const emissiveIntensityTarget = isSelected ? 1.5 : isHovered ? 1 : 0.5;
  const targetY = isSelected ? Math.sin(Date.now() * 0.002) * 0.5 : 0;

  useFrame((_, delta) => {
    if (meshRef.current) {
        const material = meshRef.current.material as THREE.MeshStandardMaterial;
        material.emissiveIntensity = THREE.MathUtils.lerp(material.emissiveIntensity, emissiveIntensityTarget, delta * 5);
        material.color.lerp(targetColor, delta * 8);
        material.emissive.copy(material.color);
        meshRef.current.position.y = THREE.MathUtils.lerp(meshRef.current.position.y, targetY, delta * 5);
    }
  });

  const handlePointerOver = (e: ThreeEvent<PointerEvent>) => {
    e.stopPropagation();
    if (onSelect) { // Only allow hover effects if the item is selectable
      setIsHovered(true);
      document.body.style.cursor = 'pointer';
    }
  };

  const handlePointerOut = (e: ThreeEvent<PointerEvent>) => {
    e.stopPropagation();
    setIsHovered(false);
    document.body.style.cursor = 'auto';
  };

  const handleClick = (e: ThreeEvent<MouseEvent>) => {
    e.stopPropagation();
    if (onSelect) {
      onSelect(district);
    }
  };

  return (
    <group position={district.position}>
        <mesh
            ref={meshRef}
            castShadow
            receiveShadow
            onClick={onSelect ? handleClick : undefined}
            onPointerOver={handlePointerOver}
            onPointerOut={handlePointerOut}
        >
            <boxGeometry args={[8, height, 8]} />
            <meshStandardMaterial
                transparent
                opacity={isUnlocked ? 0.7 : 0.3}
                wireframe={!isUnlocked}
                metalness={0.8}
                roughness={0.2}
            />
        </mesh>
        {!isUnlocked && (
            <Text
                position={[0, height / 2 + 2, 0]}
                fontSize={2}
                color="#ff4444"
                anchorX="center"
                anchorY="middle"
            >
                ?
            </Text>
        )}
    </group>
  );
};

