import React, { useRef, useMemo } from 'react';
// FIX: Add side-effect import to ensure R3F's JSX types are globally available.
import '@react-three/fiber';
// FIX: Add useThree to provide types for JSX primitives
import { useFrame, useThree } from '@react-three/fiber';
import { Cone, Cylinder, Torus } from '@react-three/drei';
import * as THREE from 'three';

interface HolographicProjectorProps {
  position: [number, number, number];
}

export const HolographicProjector: React.FC<HolographicProjectorProps> = ({ position }) => {
  // FIX: Call useThree to provide types for JSX primitives
  useThree();
  const holoRef = useRef<THREE.Group>(null!);
  const coneRef = useRef<THREE.Mesh>(null!);

  useFrame(({ clock }) => {
    if (holoRef.current) {
      holoRef.current.rotation.y = clock.getElapsedTime() * 0.5;
    }
    if (coneRef.current) {
        (coneRef.current.material as THREE.ShaderMaterial).uniforms.time.value = clock.getElapsedTime();
    }
  });

  const shaderMaterial = useMemo(() => new THREE.ShaderMaterial({
    uniforms: {
      time: { value: 0 },
      color: { value: new THREE.Color(0x00aaff) },
    },
    vertexShader: `
      varying vec2 vUv;
      void main() {
        vUv = uv;
        gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
      }
    `,
    fragmentShader: `
      uniform float time;
      uniform vec3 color;
      varying vec2 vUv;
      void main() {
        float line = step(0.01, abs(sin((vUv.y + time * 0.1) * 20.0)));
        float opacity = (1.0 - vUv.y) * 0.5;
        gl_FragColor = vec4(color, line * opacity);
      }
    `,
    transparent: true,
    depthWrite: false,
    side: THREE.DoubleSide,
    blending: THREE.AdditiveBlending,
  }), []);

  return (
    <group position={position}>
      <Cylinder args={[1, 1, 0.5, 32]} position-y={0.25}>
        <meshStandardMaterial color="#222" metalness={0.9} roughness={0.2} />
      </Cylinder>
      <group ref={holoRef} position-y={4}>
        <Torus args={[2, 0.1, 16, 100]} rotation-x={Math.PI / 2}>
          <meshStandardMaterial color="#00ffff" emissive="#00ffff" emissiveIntensity={2} toneMapped={false} />
        </Torus>
      </group>
      <Cone ref={coneRef} args={[2.5, 4, 32]} position-y={2.5}>
        <primitive object={shaderMaterial} attach="material" />
      </Cone>
    </group>
  );
};

import React, { useRef, useMemo } from 'react';
// FIX: Add side-effect import to ensure R3F's JSX types are globally available.
import '@react-three/fiber';
import { useGLTF } from '@react-three/drei';
// FIX: Add useThree to provide types for JSX primitives
import { useFrame, useThree } from '@react-three/fiber';
import * as THREE from 'three';
import { createNoise3D } from 'simplex-noise';

const MODEL_URL = 'https://raw.githubusercontent.com/wiwitmikael-a11y/3Dmodels/main/PatrollingCore.glb';
const SCALE = 4; 

// Inisialisasi fungsi noise di luar komponen untuk performa
const noise3D = createNoise3D();

interface PatrollingCoreProps {
  isPaused?: boolean;
}

export const PatrollingCore: React.FC<PatrollingCoreProps> = React.memo(({ isPaused }) => {
  // FIX: Call useThree to provide types for JSX primitives
  useThree();
  const groupRef = useRef<THREE.Group>(null!);
  const { scene } = useGLTF(MODEL_URL);

  const clonedScene = useMemo(() => scene.clone(), [scene]);
  const previousPosition = useMemo(() => new THREE.Vector3(), []);

  useFrame(({ clock }) => {
    if (!groupRef.current || isPaused) return;

    const elapsedTime = clock.getElapsedTime();
    const movementSpeed = 0.04;

    const time = elapsedTime * movementSpeed;
    const horizontalRange = 80;
    const verticalRange = 25;
    const baseHeight = 35;

    const x = noise3D(time, 0, 0) * horizontalRange;
    const z = noise3D(0, time, 0) * horizontalRange;
    const heightNoise = (noise3D(0, 0, time) + 1) / 2;
    const y = baseHeight + heightNoise * verticalRange;

    previousPosition.copy(groupRef.current.position);
    groupRef.current.position.lerp(new THREE.Vector3(x, y, z), 0.05);

    if (previousPosition.distanceTo(groupRef.current.position) > 0.01) {
       const lookAtTarget = new THREE.Vector3().copy(groupRef.current.position).add(
         new THREE.Vector3().subVectors(groupRef.current.position, previousPosition).normalize()
       );
       const tempObject = new THREE.Object3D();
       tempObject.position.copy(groupRef.current.position);
       tempObject.lookAt(lookAtTarget);
       groupRef.current.quaternion.slerp(tempObject.quaternion, 0.05);
    }
  });

  return (
    <group ref={groupRef}>
      <primitive 
        object={clonedScene} 
        scale={SCALE}
        position-y={0} 
      />
    </group>
  );
});

