import { Experience3D } from './components/Experience3D';
import { AudioProvider } from './contexts/AudioContext';
import { useAudio } from './hooks/useAudio';
import { VideoIntro } from './components/ui/VideoIntro';

interface ErrorBoundaryProps {
  children?: React.ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

// Simple Error Boundary to catch 3D crashes without killing the whole app UI
class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
  public state: ErrorBoundaryState = {
    hasError: false,
    error: null
  };

  static getDerivedStateFromError(error: Error) {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: React.ErrorInfo) {
    console.error("CRITICAL 3D ERROR:", error, errorInfo);
  }

  render() {
    if (this.state.hasError) {
      return (
        <div style={{
            position: 'absolute', inset: 0, zIndex: 999,
            display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
            backgroundColor: '#050810', color: '#ff4444', fontFamily: 'monospace', textAlign: 'center', padding: '20px'
        }}>
            <h2 style={{fontSize: '2rem', marginBottom: '10px'}}>SYSTEM FAILURE</h2>
            <p style={{color: '#888', maxWidth: '600px', marginBottom: '20px'}}>
                The 3D Reality Engine encountered a critical error.<br/>
                {this.state.error?.message || "Unknown WebGL Error"}
            </p>
            <button 
                onClick={() => window.location.reload()}
                style={{
                    background: 'transparent', border: '1px solid #ff4444', color: '#ff4444',
                    padding: '10px 30px', cursor: 'pointer', fontFamily: 'inherit', fontSize: '1rem'
                }}
            >
                REBOOT SYSTEM
            </button>
        </div>
      );
    }
    return this.props.children;
  }
}

const AppContent: React.FC = () => {
  const [appState, setAppState] = useState<'video' | 'entering' | 'experience'>('video');
  const audio = useAudio();

  const handleIntroComplete = useCallback(() => {
    audio.play('confirm');
    audio.play('gate_open', { volume: 0.8 });
    audio.playLoop('ambience', { volume: 0.2 });
    audio.playLoop('flyby', { volume: 0.15 });

    setAppState('entering');
  }, [audio]);

  const handleEntryAnimationFinish = useCallback(() => {
    setAppState('experience');
  }, []);

  const showVideo = appState === 'video';

  // RENDER STRATEGY:
  // Render Experience3D immediately behind the video.
  // The 'isWaitingToStart' flag keeps the camera locked at the gate position.
  const isWaitingToStart = appState === 'video';
  const isEntering = appState === 'entering';
  const isHudVisible = appState === 'experience';

  return (
    <>
      {showVideo && <VideoIntro onComplete={handleIntroComplete} />}

      <main style={{ width: '100vw', height: '100vh', backgroundColor: '#050810' }}>
        <ErrorBoundary>
            <Suspense fallback={null}>
                <Experience3D 
                  isHudVisible={isHudVisible} 
                  isEntering={isEntering}
                  isWaitingToStart={isWaitingToStart} 
                  onEntryFinish={handleEntryAnimationFinish} 
                />
            </Suspense>
        </ErrorBoundary>
      </main>
    </>
  );
};

const App: React.FC = () => {
  return (
    <AudioProvider>
      <AppContent />
    </AudioProvider>
  );
};

export default App;

import React, { useMemo, useRef, useLayoutEffect } from 'react';
// FIX: Add side-effect import to ensure R3F's JSX types are globally available.
import '@react-three/fiber';
import { useFrame, useThree } from '@react-three/fiber';
import * as THREE from 'three';

const BLOCK_COUNT = 150;
const MIN_RADIUS = 200; // Far outside the main districts (approx 100-120 range)
const MAX_RADIUS = 450;
const COLOR_PALETTE = ['#00aaff', '#00ffff', '#0055aa'];

export const BackgroundArchitecture: React.FC = React.memo(() => {
  useThree();
  const meshRef = useRef<THREE.InstancedMesh>(null!);
  const dummy = useMemo(() => new THREE.Object3D(), []);

  // Store random data for each block to use in animation
  const particles = useMemo(() => {
    return new Array(BLOCK_COUNT).fill(0).map(() => ({
      speed: Math.random() * 0.2 + 0.1,
      offset: Math.random() * 100,
      baseY: Math.random() * 50 - 20, // Some below ground, some floating high
      x: 0,
      z: 0,
      height: 0,
    }));
  }, []);

  useLayoutEffect(() => {
    if (!meshRef.current) return;

    for (let i = 0; i < BLOCK_COUNT; i++) {
      // Polar coordinates for distribution ring
      // Use Math.sqrt(Math.random()) for uniform distribution in a ring
      const r = Math.sqrt(Math.random()) * (MAX_RADIUS - MIN_RADIUS) + MIN_RADIUS;
      const theta = Math.random() * 2 * Math.PI;

      const x = r * Math.cos(theta);
      const z = r * Math.sin(theta);

      particles[i].x = x;
      particles[i].z = z;

      // Randomize Scale
      const width = Math.random() * 20 + 10;
      const depth = Math.random() * 20 + 10;
      const height = Math.random() * 120 + 30; // Tall skyscraper-like blocks
      particles[i].height = height;

      dummy.position.set(x, particles[i].baseY + height / 2, z);
      dummy.scale.set(width, height, depth);
      dummy.rotation.y = Math.random() * Math.PI; // Random rotation

      dummy.updateMatrix();
      meshRef.current.setMatrixAt(i, dummy.matrix);

      // Randomize color slightly for each instance
      const color = new THREE.Color(COLOR_PALETTE[Math.floor(Math.random() * COLOR_PALETTE.length)]);
      meshRef.current.setColorAt(i, color);
    }
    meshRef.current.instanceMatrix.needsUpdate = true;
    if (meshRef.current.instanceColor) meshRef.current.instanceColor.needsUpdate = true;
  }, [dummy, particles]);

  useFrame(({ clock }) => {
    if (!meshRef.current) return;

    const time = clock.getElapsedTime();

    for (let i = 0; i < BLOCK_COUNT; i++) {
        const p = particles[i];

        // Gentle floating animation
        // Using a sine wave based on time, unique speed, and random offset
        const floatingY = Math.sin(time * p.speed + p.offset) * 10;

        // Retrieve current transform (we only want to update Y position)
        meshRef.current.getMatrixAt(i, dummy.matrix);
        dummy.matrix.decompose(dummy.position, dummy.quaternion, dummy.scale);

        dummy.position.y = p.baseY + p.height / 2 + floatingY;

        dummy.updateMatrix();
        meshRef.current.setMatrixAt(i, dummy.matrix);
    }
    meshRef.current.instanceMatrix.needsUpdate = true;
  });

  return (
    <instancedMesh ref={meshRef} args={[undefined, undefined, BLOCK_COUNT]}>
      <boxGeometry args={[1, 1, 1]} /> {/* Base geometry 1x1x1, scaled via matrix */}
      <meshStandardMaterial
        color="#00aaff"
        transparent
        opacity={0.15} // Very transparent
        metalness={0.8}
        roughness={0.1}
        depthWrite={false} // Prevents z-fighting artifacts with transparency
        blending={THREE.AdditiveBlending} // Adds a nice holographic glow effect
      />
    </instancedMesh>
  );
});

import React, { useState, useCallback, Suspense, useMemo, useRef, useEffect } from 'react';
// FIX: Add a side-effect import to ensure R3F's JSX types are globally available.
import '@react-three/fiber';
import { Canvas, useThree } from '@react-three/fiber';
