      <FlyingShips
        setShipRefs={setShipRefs}
        isPaused={isPaused}
        controlledShipId={controlledShipId}
        shipInputs={shipInputs}
        fireRequest={fireRequest}
      />
      <PatrollingCore isPaused={isPaused} />
    </>
