import { useFrame, useThree } from '@react-three/fiber';
import * as THREE from 'three';
import { createNoise2D } from 'simplex-noise';

const noise2D = createNoise2D();

interface ThrustTrailProps {
    width?: number;
    length?: number;
    opacity?: number;
    color?: string;
    position?: [number, number, number];
}

export const ThrustTrail: React.FC<ThrustTrailProps> = ({ width = 0.3, length = 3, opacity = 0.5, color = '#00ffff', position = [0, 0, 0] }) => {
    // FIX: Call useThree to provide types for JSX primitives
    useThree();
    const meshRef = useRef<THREE.Mesh>(null!);

    // This component renders a cone pointing towards -Z (backwards).
    // We offset it by half its length so its base starts at the provided `position`.
    const trailPosition: [number, number, number] = [position[0], position[1], position[2] - length / 2];

    useFrame(({ clock }) => {
        if (meshRef.current) {
            const time = clock.getElapsedTime();
            const material = meshRef.current.material as THREE.MeshStandardMaterial;

            // Use noise to create a more chaotic, fiery flicker effect
            const baseFrequency = 15;

            // Flicker both length and width slightly differently and chaotically
            const lengthFlicker = 1.0 + (noise2D(time * baseFrequency, 0) + 1) / 2 * 0.3; // Range [1.0, 1.3]
            const widthFlicker = 1.0 + (noise2D(0, time * (baseFrequency + 2)) + 1) / 2 * 0.2; // Range [1.0, 1.2]

            // Y-axis on the mesh corresponds to the cone's height/length
            meshRef.current.scale.set(widthFlicker, lengthFlicker, widthFlicker);

            // Flicker opacity for a more dynamic feel
            material.opacity = opacity * (0.7 + (noise2D(time * 5, time * 5) + 1) / 2 * 0.3); // Range [0.7, 1.0] * base opacity
        }
    });

    return (
        <mesh ref={meshRef} position={trailPosition} rotation-x={Math.PI / 2}>
            <coneGeometry args={[width, length, 8]} />
            <meshStandardMaterial
                color={color}
                emissive={color}
                emissiveIntensity={4}
                transparent
                opacity={opacity}
                blending={THREE.AdditiveBlending}
                depthWrite={false}
                toneMapped={false}
            />
        </mesh>
    );
};

import React, { useMemo, useRef, useLayoutEffect } from 'react';
// FIX: Add explicit type augmentation for R3F elements
import { ThreeElements } from '@react-three/fiber'
declare global {
  namespace JSX {
    interface IntrinsicElements extends ThreeElements {}
  }
}
import { useFrame, useThree } from '@react-three/fiber';
import * as THREE from 'three';

const BLOCK_COUNT = 150;
const MIN_RADIUS = 200; // Far outside the main districts (approx 100-120 range)
const MAX_RADIUS = 450;
const COLOR_PALETTE = ['#00aaff', '#00ffff', '#0055aa'];

export const BackgroundArchitecture: React.FC = React.memo(() => {
  useThree();
  const meshRef = useRef<THREE.InstancedMesh>(null!);
  const dummy = useMemo(() => new THREE.Object3D(), []);

  // Store random data for each block to use in animation
  const particles = useMemo(() => {
    return new Array(BLOCK_COUNT).fill(0).map(() => ({
      speed: Math.random() * 0.2 + 0.1,
      offset: Math.random() * 100,
      baseY: Math.random() * 50 - 20, // Some below ground, some floating high
      x: 0,
      z: 0,
      height: 0,
    }));
  }, []);

  useLayoutEffect(() => {
    if (!meshRef.current) return;

    for (let i = 0; i < BLOCK_COUNT; i++) {
      // Polar coordinates for distribution ring
      // Use Math.sqrt(Math.random()) for uniform distribution in a ring
      const r = Math.sqrt(Math.random()) * (MAX_RADIUS - MIN_RADIUS) + MIN_RADIUS;
      const theta = Math.random() * 2 * Math.PI;

      const x = r * Math.cos(theta);
      const z = r * Math.sin(theta);

      particles[i].x = x;
      particles[i].z = z;

      // Randomize Scale
      const width = Math.random() * 20 + 10;
      const depth = Math.random() * 20 + 10;
      const height = Math.random() * 120 + 30; // Tall skyscraper-like blocks
      particles[i].height = height;

      dummy.position.set(x, particles[i].baseY + height / 2, z);
      dummy.scale.set(width, height, depth);
      dummy.rotation.y = Math.random() * Math.PI; // Random rotation

      dummy.updateMatrix();
      meshRef.current.setMatrixAt(i, dummy.matrix);

      // Randomize color slightly for each instance
      const color = new THREE.Color(COLOR_PALETTE[Math.floor(Math.random() * COLOR_PALETTE.length)]);
      meshRef.current.setColorAt(i, color);
    }
    meshRef.current.instanceMatrix.needsUpdate = true;
    if (meshRef.current.instanceColor) meshRef.current.instanceColor.needsUpdate = true;
  }, [dummy, particles]);

  useFrame(({ clock }) => {
    if (!meshRef.current) return;

    const time = clock.getElapsedTime();

    for (let i = 0; i < BLOCK_COUNT; i++) {
        const p = particles[i];

        // Gentle floating animation
        // Using a sine wave based on time, unique speed, and random offset
        const floatingY = Math.sin(time * p.speed + p.offset) * 10;

        // Retrieve current transform (we only want to update Y position)
        meshRef.current.getMatrixAt(i, dummy.matrix);
        dummy.matrix.decompose(dummy.position, dummy.quaternion, dummy.scale);

        dummy.position.y = p.baseY + p.height / 2 + floatingY;

        dummy.updateMatrix();
        meshRef.current.setMatrixAt(i, dummy.matrix);
    }
    meshRef.current.instanceMatrix.needsUpdate = true;
  });

  return (
    <instancedMesh ref={meshRef} args={[undefined, undefined, BLOCK_COUNT]}>
      <boxGeometry args={[1, 1, 1]} /> {/* Base geometry 1x1x1, scaled via matrix */}
      <meshStandardMaterial
        color="#00aaff"
        transparent
        opacity={0.15} // Very transparent
        metalness={0.8}
        roughness={0.1}
        depthWrite={false} // Prevents z-fighting artifacts with transparency
        blending={THREE.AdditiveBlending} // Adds a nice holographic glow effect
      />
    </instancedMesh>
  );
});

import React, { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';

const vertexShader = `
varying vec3 vWorldPosition;
varying vec2 vUv;

void main() {
  vUv = uv;
  vec4 worldPosition = modelMatrix * vec4(position, 1.0);
  vWorldPosition = worldPosition.xyz;
  gl_Position = projectionMatrix * viewMatrix * worldPosition;
}
`;

const fragmentShader = `
uniform float uTime;
uniform vec3 uColor1;
uniform vec3 uColor2;
varying vec3 vWorldPosition;
varying vec2 vUv;

// Simplex 2D noise function
vec3 permute(vec3 x) { return mod(((x*34.0)+1.0)*x, 289.0); }

float snoise(vec2 v){
  const vec4 C = vec4(0.211324865405187, 0.366025403784439,
           -0.577350269189626, 0.024390243902439);
  vec2 i  = floor(v + dot(v, C.yy) );
  vec2 x0 = v -   i + dot(i, C.xx);
  vec2 i1;
  i1 = (x0.x > x0.y) ? vec2(1.0, 0.0) : vec2(0.0, 1.0);
  vec4 x12 = x0.xyxy + C.xxzz;
  x12.xy -= i1;
  i = mod(i, 289.0);
  vec3 p = permute( permute( i.y + vec3(0.0, i1.y, 1.0 ))
  + i.x + vec3(0.0, i1.x, 1.0 ));
  vec3 m = max(0.5 - vec3(dot(x0,x0), dot(x12.xy,x12.xy), dot(x12.zw,x12.zw)), 0.0);
  m = m*m ;
  m = m*m ;
  vec3 x = 2.0 * fract(p * C.www) - 1.0;
  vec3 h = abs(x) - 0.5;
  vec3 ox = floor(x + 0.5);
  vec3 a0 = x - ox;
  m *= 1.79284291400159 - 0.85373472095314 * ( a0*a0 + h*h );
  vec3 g;
  g.x  = a0.x  * x0.x  + h.x  * x0.y;
  g.yz = a0.yz * x12.xz + h.yz * x12.yw;
  return 130.0 * dot(m, g);
}

void main() {
  // Normalize height for the dome
  float height = normalize(vWorldPosition).y;

  // Create waving curtain effect
  float time = uTime * 0.2;
  float noise1 = snoise(vec2(vUv.x * 5.0 + time, vUv.y * 2.0));
  float noise2 = snoise(vec2(vUv.x * 12.0 - time * 0.5, vUv.y * 5.0));

  // Combine noise to create streaks
  float combinedNoise = (noise1 + noise2 * 0.5);

  // Intense bands logic
  float intensity = smoothstep(0.3, 0.8, combinedNoise);

  // Fade out at horizon (bottom) and zenith (very top)
  float horizonFade = smoothstep(0.0, 0.3, height);
  float zenithFade = 1.0 - smoothstep(0.7, 1.0, height);

  // Color mixing
  vec3 color = mix(uColor1, uColor2, vUv.y + noise1 * 0.2);

  // Final Alpha
  float alpha = intensity * horizonFade * zenithFade * 0.4; // 0.4 max opacity

  gl_FragColor = vec4(color, alpha);
}
`;

export const AuroraBorealis: React.FC = React.memo(() => {
  const meshRef = useRef<THREE.Mesh>(null!);

  const uniforms = useMemo(() => ({
    uTime: { value: 0 },
    // Cyan to Purple Gradient matching the theme
    uColor1: { value: new THREE.Color('#00ffff') }, 
    uColor2: { value: new THREE.Color('#bd00ff') },
  }), []);

  useFrame(({ clock }) => {
    if (meshRef.current) {
      const material = meshRef.current.material as THREE.ShaderMaterial;
      material.uniforms.uTime.value = clock.getElapsedTime();
    }
  });

  return (
    <mesh ref={meshRef} position={[0, -50, 0]} scale={[1, 0.6, 1]}>
      {/* Huge dome surrounding the city */}
      <sphereGeometry args={[480, 64, 32, 0, Math.PI * 2, 0, Math.PI * 0.5]} />
      <shaderMaterial
        vertexShader={vertexShader}
        fragmentShader={fragmentShader}
        uniforms={uniforms}
        side={THREE.BackSide} // Render on the inside of the sphere
        transparent={true}
        blending={THREE.AdditiveBlending} // Adds light to existing sky without blocking stars
        depthWrite={false} // Don't block other transparent objects
      />
    </mesh>
  );
});

import React, { useState, useCallback, Suspense, useMemo, useRef, useEffect } from 'react';
// FIX: Add explicit type augmentation for R3F elements
import { ThreeElements } from '@react-three/fiber'
declare global {
  namespace JSX {
    interface IntrinsicElements extends ThreeElements {}
  }
}
import { Canvas, useThree } from '@react-three/fiber';
import { OrbitControls, Sky, Preload, Stars } from '@react-three/drei';
import type { OrbitControls as OrbitControlsImpl } from 'three-stdlib';
import { EffectComposer, Bloom } from '@react-three/postprocessing';
import * as THREE from 'three';

import { CityModel } from './scene/CityModel';
import { FlyingShips, shipsData } from './scene/FlyingShips';
import { DistrictRenderer } from './scene/DistrictRenderer';
import { portfolioData, OVERVIEW_CAMERA_POSITION } from '../constants';
import type { CityDistrict, ShipControlMode, ShipInputState } from '../types';
import { CameraRig } from './CameraRig';
import { HUD } from './ui/HUD';
import { ProceduralTerrain } from './scene/ProceduralTerrain';
import HolographicInfoPanel from './scene/HolographicInfoPanel';
import { QuickNavMenu } from './ui/QuickNavMenu';
import { ProjectSelectionPanel } from './ui/ProjectSelectionPanel';
import { PatrollingCore } from './scene/PatrollingCore';
import { CalibrationGrid } from './scene/CalibrationGrid';
import { BuildModeController } from './scene/BuildModeController';
import { ExportLayoutModal } from './ui/ExportLayoutModal';
import { useShipControls } from '../hooks/useShipControls';
import { HintsPanel } from './ui/HintsPanel';
import { useAudio } from '../hooks/useAudio';
import { InitialHintTooltip } from './ui/InitialHintTooltip';
import { BackgroundArchitecture } from './scene/BackgroundArchitecture';
import { AuroraBorealis } from './scene/AuroraBorealis';


// Define the sun's position for a sunset glow near the horizon
const sunPosition: [number, number, number] = [100, 2, -100]; // Lower sun for a more dramatic sunset
const sunColor = '#ffd0b3'; // Warmer light

interface SceneContentProps {
  districts: CityDistrict[];
  selectedDistrict: CityDistrict | null;
  handleDistrictSelect: (district: CityDistrict) => void;
  isCalibrationMode: boolean;
  heldDistrictId: string | null;
  setHeldDistrictId: (id: string | null) => void;
  setShipRefs: (refs: React.RefObject<THREE.Group>[]) => void;
  isPaused: boolean;
  controlledShipId: string | null;
  shipInputs: ShipInputState;
  fireRequest: number;
}

const SceneContent: React.FC<SceneContentProps> = ({ districts, selectedDistrict, handleDistrictSelect, isCalibrationMode, heldDistrictId, setHeldDistrictId, setShipRefs, isPaused, controlledShipId, shipInputs, fireRequest }) => {
  // Call useThree hook to ensure R3F types are loaded for JSX primitives.
  useThree();

  return (
    <>
      <ambientLight intensity={0.5} color={sunColor} />
      <directionalLight
        position={sunPosition}
        intensity={2.5}
        castShadow
        shadow-mapSize-width={1024}
        shadow-mapSize-height={1024}
        shadow-camera-far={500}
        shadow-camera-left={-200}
        shadow-camera-right={200}
        shadow-camera-top={200}
        shadow-camera-bottom={-200}
        color={sunColor}
      />

      {/* Sky Base */}
      <Sky 
        distance={450000} 
        sunPosition={new THREE.Vector3(...sunPosition)} 
        inclination={0} 
        azimuth={0.25} 
        mieCoefficient={0.005} 
        mieDirectionalG={0.7} 
        rayleigh={3} 
        turbidity={10} 
      />

      {/* Stars for background depth */}
      <Stars radius={300} depth={50} count={5000} factor={4} saturation={0} fade speed={1} />

      {/* Dynamic Aurora Overlay */}
      <AuroraBorealis />

      <CityModel />
      <ProceduralTerrain />
      <BackgroundArchitecture />
      <DistrictRenderer
        districts={districts}
        selectedDistrict={selectedDistrict}
        onDistrictSelect={handleDistrictSelect}
        isCalibrationMode={isCalibrationMode}
        heldDistrictId={heldDistrictId}
        onSetHeldDistrict={setHeldDistrictId}
      />
      <FlyingShips
        setShipRefs={setShipRefs}
        isPaused={isPaused}
        controlledShipId={controlledShipId}
        shipInputs={shipInputs}
        fireRequest={fireRequest}
      />
      <PatrollingCore isPaused={isPaused} />
    </>
  );
};

interface Experience3DProps {
  isHudVisible: boolean;
  isEntering: boolean;
  isWaitingToStart: boolean; // Controls if camera is locked at gate
  onEntryFinish?: () => void; // New prop callback
}

export const Experience3D: React.FC<Experience3DProps> = ({ isHudVisible, isEntering, isWaitingToStart, onEntryFinish }) => {
  const [districts, setDistricts] = useState<CityDistrict[]>(portfolioData);
  const [selectedDistrict, setSelectedDistrict] = useState<CityDistrict | null>(null);
  const [isAnimating, setIsAnimating] = useState(false);
  const [showContentPanel, setShowContentPanel] = useState(false);
  const [infoPanelItem, setInfoPanelItem] = useState<CityDistrict | null>(null);
  const [isNavMenuOpen, setIsNavMenuOpen] = useState(false);
  const [isHintsOpen, setIsHintsOpen] = useState(false);
  const audio = useAudio();

  const [pov, setPov] = useState<'main' | 'ship'>('main');
  const [shipRefs, setShipRefs] = useState<React.RefObject<THREE.Group>[]>([]);
  const [targetShipRef, setTargetShipRef] = useState<React.RefObject<THREE.Group> | null>(null);
  const [isAutoRotating, setIsAutoRotating] = useState(true);
  const [isCalibrationMode] = useState(false);
  const idleTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const [isTouring, setIsTouring] = useState(false);
  const [tourIndex, setTourIndex] = useState(0);

  const isTouchDevice = useMemo(() => 'ontouchstart' in window || navigator.maxTouchPoints > 0, []);

  const [shipControlMode, setShipControlMode] = useState<ShipControlMode>('follow');
  const [controlledShipId, setControlledShipId] = useState<string | null>(null);
  const [fireRequest, setFireRequest] = useState(0);

  const shipKeyboardInputs = useShipControls(shipControlMode === 'manual' && !isTouchDevice);
  const [shipTouchInputs, setShipTouchInputs] = useState<ShipInputState>({ forward: 0, turn: 0, ascend: 0, roll: 0 });
  const shipInputs = isTouchDevice ? shipTouchInputs : shipKeyboardInputs;

  const [heldDistrictId, setHeldDistrictId] = useState<string | null>(null);
  const [isExportModalOpen] = useState(false);
  const [exportedLayoutJson] = useState('');

  const controlsRef = useRef<OrbitControlsImpl>(null);
  const isPaused = isCalibrationMode;

  const isAnyPanelOpen = showContentPanel || isNavMenuOpen || isHintsOpen;

  const [showInitialHint, setShowInitialHint] = useState(false);

  // Effect to trigger the cinematic entry camera animation
  useEffect(() => {
    if (isEntering) {
      setIsAnimating(true);
    }
  }, [isEntering]);

  // New effect to show the initial tooltip once
  useEffect(() => {
    if (isHudVisible) {
        const timer = setTimeout(() => {
            setShowInitialHint(true);
        }, 1500); // Show after 1.5s delay
        return () => clearTimeout(timer);
    }
  }, [isHudVisible]);


  const navDistricts = useMemo(() => {
    const majorDistricts = districts.filter(d => d.type === 'major');
    const order: string[] = ['skills-matrix', 'visual-arts', 'nova-forge', 'defi-data-vault', 'contact', 'nexus-core'];
    return [...majorDistricts].sort((a, b) => {
        let indexA = order.indexOf(a.id);
        let indexB = order.indexOf(b.id);
        if (indexA === -1) indexA = Infinity;
        if (indexB === -1) indexB = Infinity;
        return indexA - indexB;
    });
  }, [districts]);

  const tourStops = useMemo(() => {
    const tourDistrictIds = ['skills-matrix', 'visual-arts', 'nova-forge'];
    const stops = tourDistrictIds.map(id => districts.find(d => d.id === id)).filter((d): d is CityDistrict => !!d);
    return [...stops, null];
  }, [districts]);

  const handleDistrictSelect = useCallback((district: CityDistrict) => {
    if (isAnimating || isCalibrationMode || district.id === selectedDistrict?.id) return;
    setIsTouring(false);
    setShowContentPanel(false);
    setInfoPanelItem(null);
    setIsAutoRotating(false);
    setSelectedDistrict(districts.find(d => d.id === district.id) || null);
    setIsAnimating(true);
    audio.play('confirm');
  }, [selectedDistrict, isAnimating, districts, isCalibrationMode, audio]);

  const isDetailViewActive = showContentPanel || !!infoPanelItem || !!selectedDistrict;

  const resetIdleTimer = useCallback(() => {
    if (idleTimerRef.current) clearTimeout(idleTimerRef.current);
    idleTimerRef.current = setTimeout(() => {
        if (pov === 'main' && !isDetailViewActive && !isCalibrationMode) {
            setIsAutoRotating(true);
        }
    }, 60000);
  }, [pov, isDetailViewActive, isCalibrationMode]);

  const handleInteractionStart = useCallback(() => {
      setIsTouring(false);
      setIsAutoRotating(false);
      if (idleTimerRef.current) clearTimeout(idleTimerRef.current);
  }, []);

  const handleInteractionEnd = useCallback(() => {
      resetIdleTimer();
  }, [resetIdleTimer]);

  const handleControlsChange = useCallback(() => {
    if (controlsRef.current) {
      const target = controlsRef.current.target;
      const boundary = 150;
      target.x = THREE.MathUtils.clamp(target.x, -boundary, boundary);
      target.z = THREE.MathUtils.clamp(target.z, -boundary, boundary);
      target.y = THREE.MathUtils.clamp(target.y, 0, 50);
    }
  }, []);

  useEffect(() => {
    resetIdleTimer();
    return () => {
        if (idleTimerRef.current) clearTimeout(idleTimerRef.current);
    };
  }, [resetIdleTimer]);

  const handleGoHome = useCallback(() => {
    if (isAnimating) return;
    audio.play('confirm');
    setIsTouring(false);
    setPov('main');
    setSelectedDistrict(null);
    setIsAnimating(true);
    setShowContentPanel(false);
    setInfoPanelItem(null);
    setTargetShipRef(null);
    setShipControlMode('follow');
    setControlledShipId(null);
  }, [isAnimating, audio]);

  const onAnimationFinish = useCallback(() => {
    if (isEntering) { // Special case for the entry animation finishing
      setIsAnimating(false);
      resetIdleTimer();
      if (controlsRef.current) {
        controlsRef.current.target.set(0, 5, 0); // Set initial target
        controlsRef.current.update();
      }
      if (onEntryFinish) onEntryFinish();
      return;
    }

    if (isTouring) {
      const nextIndex = tourIndex + 1;
      if (nextIndex < tourStops.length) {
        setTourIndex(nextIndex);
        setSelectedDistrict(tourStops[nextIndex]);
      } else {
        setIsTouring(false);
        setIsAnimating(false);
        setSelectedDistrict(null);
        resetIdleTimer();
        if (controlsRef.current) {
          controlsRef.current.target.set(0, 5, 0);
          controlsRef.current.update();
        }
      }
      return;
    }

    setIsAnimating(false);
    if (selectedDistrict) {
      setShowContentPanel(true);
      if (controlsRef.current && selectedDistrict.cameraFocus) {
        const { lookAt } = selectedDistrict.cameraFocus;
        controlsRef.current.target.set(lookAt[0], lookAt[1], lookAt[2]);
        controlsRef.current.update();
      }
    } else if (pov === 'main' && !isCalibrationMode) {
      resetIdleTimer();
      if (controlsRef.current) {
        controlsRef.current.target.set(0, 5, 0);
        controlsRef.current.update();
      }
    }
  }, [isEntering, isTouring, tourIndex, tourStops, selectedDistrict, pov, isCalibrationMode, resetIdleTimer, onEntryFinish]);

  const handleClosePanel = useCallback(() => {
    setShowContentPanel(false);
    setInfoPanelItem(null);
    setSelectedDistrict(null);
    setIsAnimating(true);
    audio.play('panel_close');
  }, [audio]);

  const handleToggleNavMenu = useCallback(() => setIsNavMenuOpen(prev => {
    if (!prev) audio.play('panel_open'); else audio.play('panel_close');
    return !prev;
  }), [audio]);

  const handleToggleHints = useCallback(() => setIsHintsOpen(prev => {
    if (!prev) audio.play('panel_open'); else audio.play('panel_close');
    return !prev;
  }), [audio]);

  const handleSetPov = useCallback((newPov: 'main' | 'ship') => {
    if (newPov === 'ship' && shipRefs.length > 0) {
      audio.play('confirm');
      const currentShipIndex = shipRefs.findIndex(ref => ref.current === targetShipRef?.current);
      const nextShipIndex = (currentShipIndex + 1) % shipRefs.length;
      setTargetShipRef(shipRefs[nextShipIndex]);
      setPov('ship');
      setSelectedDistrict(null);
      setIsAnimating(true);
    } else {
      setPov('main');
      setTargetShipRef(null);
      if (pov === 'ship') {
        setSelectedDistrict(null);
        setIsAnimating(true);
      }
    }
  }, [shipRefs, targetShipRef, pov, audio]);

  const handleToggleShipControl = useCallback(() => {
    if (shipControlMode === 'follow') {
      if (targetShipRef?.current) {
        audio.play('pilot_engage');
        audio.playLoop('engine_hum', { volume: 0.1 });
        const shipIndex = shipRefs.findIndex(ref => ref.current === targetShipRef.current);
        setControlledShipId(shipsData[shipIndex].id);
        setShipControlMode('manual');
        if (controlsRef.current) controlsRef.current.enabled = false;
      }
    } else {
      audio.play('pilot_disengage');
      audio.stop('engine_hum');
      setShipControlMode('follow');
      setControlledShipId(null);
    }
  }, [shipControlMode, targetShipRef, shipRefs, audio]);

  const handleFire = useCallback(() => {
    audio.play('laser');
    setFireRequest(prev => prev + 1)
  }, [audio]);

  const handleCanvasPointerDown = (e: React.PointerEvent) => {
    handleInteractionStart();
    if (shipControlMode === 'manual' && e.button === 0) handleFire();
  };

  const hudContext = useMemo(() => {
    if (shipControlMode === 'manual') return 'shipManual';
    if (pov === 'ship') return 'shipFollow';
    return 'overview';
  }, [shipControlMode, pov]);

  return (
    <>
      <Canvas
        shadows
        // PERFORMANCE FIX: Limit pixel ratio to 1.5 to prevent lag on Retina/4K displays
        dpr={[1, 1.5]}
        camera={{ position: OVERVIEW_CAMERA_POSITION, fov: 50, near: 1, far: 1000 }}
        onPointerDown={handleCanvasPointerDown}
        onPointerUp={handleInteractionEnd}
        onWheel={handleInteractionStart}
      >
        <Suspense fallback={null}>
            <SceneContent
              districts={districts}
              selectedDistrict={selectedDistrict}
              handleDistrictSelect={handleDistrictSelect}
              isCalibrationMode={isCalibrationMode}
              heldDistrictId={heldDistrictId}
              setHeldDistrictId={setHeldDistrictId}
              setShipRefs={setShipRefs}
              isPaused={isPaused}
              controlledShipId={controlledShipId}
              shipInputs={shipInputs}
              fireRequest={fireRequest}
            />
            {/* Preload all assets to prevent popping when animation starts */}
            <Preload all />
        </Suspense>

        {isCalibrationMode && <CalibrationGrid size={250} />}
        {heldDistrictId && (
            <BuildModeController
                districts={districts}
                setDistricts={setDistricts}
                heldDistrictId={heldDistrictId}
                onPlaceDistrict={() => setHeldDistrictId(null)}
                gridSize={250}
                gridDivisions={25}
            />
        )}

        <CameraRig 
          selectedDistrict={selectedDistrict} 
          onAnimationFinish={onAnimationFinish} 
          isAnimating={isAnimating} 
          pov={pov}
          targetShipRef={targetShipRef}
          isCalibrationMode={isCalibrationMode}
          isEntering={isEntering}
          isWaitingToStart={isWaitingToStart} 
        />

        <OrbitControls
          ref={controlsRef}
          enableDamping
          dampingFactor={0.1}
          autoRotate={isAutoRotating}
          autoRotateSpeed={0.2}
          minDistance={15}
          maxDistance={300}
          maxPolarAngle={Math.PI / 2.1}
          enablePan={!isCalibrationMode}
          target={[0, 5, 0]}
          onChange={handleControlsChange}
          enabled={!isAnimating && !isEntering && !isWaitingToStart && pov !== 'ship'}
        />

        <EffectComposer>
          {/* PERFORMANCE FIX: Removed Noise effect which is expensive on low-power devices/Opera */}
          {/* <Noise premultiply blendFunction={BlendFunction.ADD} opacity={0.05} /> */}
          <Bloom luminanceThreshold={1.2} intensity={0.6} levels={8} mipmapBlur />
        </EffectComposer>

        {infoPanelItem && <HolographicInfoPanel district={infoPanelItem} onClose={() => setInfoPanelItem(null)} />}

      </Canvas>
      {showInitialHint && <InitialHintTooltip />}
      <div
        className={`hud-container ${isHudVisible ? 'visible' : ''}`}
        style={{ pointerEvents: isHudVisible ? 'auto' : 'none' }}
      >
        <HUD 
          selectedDistrict={selectedDistrict}
          onToggleNavMenu={handleToggleNavMenu}
          onToggleHints={handleToggleHints}
          pov={pov}
          onSetPov={handleSetPov}
          onGoHome={handleGoHome}
          isCalibrationMode={isCalibrationMode}
          heldDistrictId={heldDistrictId}
          shipControlMode={shipControlMode}
          onToggleShipControl={handleToggleShipControl}
          onFire={handleFire}
          isTouchDevice={isTouchDevice}
          onShipTouchInputChange={setShipTouchInputs}
          isAnyPanelOpen={isAnyPanelOpen}
        />
        <QuickNavMenu 
          isOpen={isNavMenuOpen}
          onClose={handleToggleNavMenu}
          onSelectDistrict={(d) => {
            handleDistrictSelect(d);
            setIsNavMenuOpen(false);
          }}
          districts={navDistricts}
        />
        <ProjectSelectionPanel
          isOpen={showContentPanel}
          district={selectedDistrict}
          onClose={handleClosePanel}
        />
        <HintsPanel
          isOpen={isHintsOpen}
          onClose={handleToggleHints}
          context={hudContext}
        />
        <ExportLayoutModal
            isOpen={isExportModalOpen}
            onClose={() => { /* setIsExportModalOpen(false) */ }}
            jsonData={exportedLayoutJson}
        />
      </div>
    </>
  );
};

