const fragmentShader = `
uniform float uTime;
uniform vec3 uColor1;
uniform vec3 uColor2;
varying vec3 vWorldPosition;
varying vec2 vUv;

// Simplex 2D noise
vec3 permute(vec3 x) { return mod(((x*34.0)+1.0)*x, 289.0); }
float snoise(vec2 v){
  const vec4 C = vec4(0.211324865405187, 0.366025403784439,
           -0.577350269189626, 0.024390243902439);
  vec2 i  = floor(v + dot(v, C.yy) );
  vec2 x0 = v -   i + dot(i, C.xx);
  vec2 i1;
  i1 = (x0.x > x0.y) ? vec2(1.0, 0.0) : vec2(0.0, 1.0);
  vec4 x12 = x0.xyxy + C.xxzz;
  x12.xy -= i1;
  i = mod(i, 289.0);
  vec3 p = permute( permute( i.y + vec3(0.0, i1.y, 1.0 ))
  + i.x + vec3(0.0, i1.x, 1.0 ));
  vec3 m = max(0.5 - vec3(dot(x0,x0), dot(x12.xy,x12.xy), dot(x12.zw,x12.zw)), 0.0);
  m = m*m ;
  m = m*m ;
  vec3 x = 2.0 * fract(p * C.www) - 1.0;
  vec3 h = abs(x) - 0.5;
  vec3 ox = floor(x + 0.5);
  vec3 a0 = x - ox;
  m *= 1.79284291400159 - 0.85373472095314 * ( a0*a0 + h*h );
  vec3 g;
  g.x  = a0.x  * x0.x  + h.x  * x0.y;
  g.yz = a0.yz * x12.xz + h.yz * x12.yw;
  return dot(m, g);
}

void main() {
    float time = uTime * 0.1;

    // Apply the original UV for now
    vec2 uv = vUv;

    // Use Simplex Noise for vertical streaking effect
    float noise = snoise(vec2(uv.x * 2.0, uv.y * 5.0 + time * 0.5));
    // Apply a wave effect for movement
    float wave = sin(uv.x * 10.0 + time * 2.0);
    // Combine noise and wave for an undulating effect
    float intensity = noise * 0.5 + wave * 0.3 + 0.5;

    // Apply color gradient from bottom (cyan) to top (purple)
    vec3 color = mix(uColor1, uColor2, uv.y);
    // Apply intensity to the color
    vec3 finalColor = color * intensity;

    // Smooth out the bottom of the aurora
    float bottomMask = smoothstep(0.0, 0.1, uv.y);
    finalColor *= bottomMask;

    gl_FragColor = vec4(finalColor, 1.0);
}
`;
