import React, { useMemo } from 'react';
import * as THREE from 'three';
import { CityDistrict } from '../../types';

interface CityBaseProps {
  districts: CityDistrict[];
}

const CONNECTOR_WIDTH = 4;
const PLATFORM_COLOR = '#1a1a2e';
const GLOW_COLOR = '#00ffff';

export const CityBase: React.FC<CityBaseProps> = ({ districts }) => {
  const majorDistricts = useMemo(() => districts.filter(d => d.type === 'major'), [districts]);
  const nexus = districts.find(d => d.id === 'nexus-core');
  const centerPos = nexus ? new THREE.Vector3(...nexus.position) : new THREE.Vector3(0, 0, 0);

  // Generate paths from center to each district
  const connectors = useMemo(() => {
    return majorDistricts.map((district) => {
      if (district.id === 'nexus-core') return null;

      const targetPos = new THREE.Vector3(...district.position);
      const direction = new THREE.Vector3().subVectors(targetPos, centerPos);
      const length = direction.length();
      const midPoint = new THREE.Vector3().addVectors(centerPos, targetPos).multiplyScalar(0.5);

      // Calculate rotation to face the target
      const angle = Math.atan2(direction.x, direction.z);

      return (
        <group key={`conn-${district.id}`}>
          {/* The Road/Path */}
          <mesh 
            position={[midPoint.x, -5.8, midPoint.z]} 
            rotation={[0, angle, 0]}
            receiveShadow
          >
            <boxGeometry args={[CONNECTOR_WIDTH, 1, length]} />
            <meshStandardMaterial 
              color={PLATFORM_COLOR} 
              metalness={0.8} 
              roughness={0.2} 
            />
          </mesh>

          {/* Glowing Circuit Line on top of the road */}
          <mesh 
            position={[midPoint.x, -5.2, midPoint.z]} 
            rotation={[-Math.PI / 2, 0, angle]}
          >
            <planeGeometry args={[CONNECTOR_WIDTH * 0.2, length]} />
            <meshBasicMaterial color={GLOW_COLOR} transparent opacity={0.6} />
          </mesh>

          {/* District Platform Base (Hexagonal-ish cylinder) */}
          <mesh position={[targetPos.x, -6, targetPos.z]} receiveShadow>
            <cylinderGeometry args={[15, 18, 2, 6]} />
            <meshStandardMaterial 
              color={PLATFORM_COLOR} 
              metalness={0.9} 
              roughness={0.1}
              emissive={GLOW_COLOR}
              emissiveIntensity={0.2}
            />
          </mesh>
        </group>
      );
    });
  }, [majorDistricts, centerPos]);

  return (
    <group>
      {/* Central Hub Platform */}
      <mesh position={[centerPos.x, -6, centerPos.z]} receiveShadow>
        <cylinderGeometry args={[25, 30, 2, 8]} />
        <meshStandardMaterial 
          color={PLATFORM_COLOR} 
          metalness={0.9} 
          roughness={0.1}
        />
      </mesh>

      {/* Central Glow Ring */}
      <mesh position={[centerPos.x, -4.9, centerPos.z]} rotation={[-Math.PI/2, 0, 0]}>
        <ringGeometry args={[18, 20, 32]} />
        <meshBasicMaterial color={GLOW_COLOR} transparent opacity={0.5} side={THREE.DoubleSide} />
      </mesh>

      {connectors}
    </group>
  );
};

