  }, [districts]);

  const tourStops = useMemo(() => {
    const tourDistrictIds = ['skills-matrix', 'visual-arts', 'nova-forge'];
    const stops = tourDistrictIds.map(id => districts.find(d => d.id === id)).filter((d): d is CityDistrict => !!d);
    return [...stops, null];
  }, [districts]);

  const handleDistrictSelect = useCallback((district: CityDistrict) => {
    if (isAnimating || isCalibrationMode || district.id === selectedDistrict?.id) return;
    setIsTouring(false);
    setShowContentPanel(false);
    setInfoPanelItem(null);
    setIsAutoRotating(false);
    setSelectedDistrict(districts.find(d => d.id === district.id) || null);
    setIsAnimating(true);
    audio.play('confirm');
  }, [selectedDistrict, isAnimating, districts, isCalibrationMode, audio]);

  const isDetailViewActive = showContentPanel || !!infoPanelItem || !!selectedDistrict;

  const resetIdleTimer = useCallback(() => {
    if (idleTimerRef.current) clearTimeout(idleTimerRef.current);
    idleTimerRef.current = setTimeout(() => {
        if (pov === 'main' && !isDetailViewActive && !isCalibrationMode) {
            setIsAutoRotating(true);
        }
    }, 60000);
  }, [pov, isDetailViewActive, isCalibrationMode]);

  const handleInteractionStart = useCallback(() => {
      setIsTouring(false);
      setIsAutoRotating(false);
      if (idleTimerRef.current) clearTimeout(idleTimerRef.current);
  }, []);

  const handleInteractionEnd = useCallback(() => {
      resetIdleTimer();
  }, [resetIdleTimer]);

  const handleControlsChange = useCallback(() => {
    if (controlsRef.current) {
      const target = controlsRef.current.target;
      const boundary = 150;
      target.x = THREE.MathUtils.clamp(target.x, -boundary, boundary);
      target.z = THREE.MathUtils.clamp(target.z, -boundary, boundary);
      target.y = THREE.MathUtils.clamp(target.y, 0, 50);
    }
  }, []);

  useEffect(() => {
    resetIdleTimer();
    return () => {
        if (idleTimerRef.current) clearTimeout(idleTimerRef.current);
    };
  }, [resetIdleTimer]);

  const handleGoHome = useCallback(() => {
    if (isAnimating) return;
    audio.play('confirm');
    setIsTouring(false);
    setPov('main');
    setSelectedDistrict(null);
    setIsAnimating(true);
    setShowContentPanel(false);
    setInfoPanelItem(null);
    setTargetShipRef(null);
    setShipControlMode('follow');
    setControlledShipId(null);
  }, [isAnimating, audio]);

  const onAnimationFinish = useCallback(() => {
    if (isEntering) { // Special case for the entry animation finishing
      setIsAnimating(false);
      resetIdleTimer();
      if (controlsRef.current) {
        controlsRef.current.target.set(0, 5, 0); // Set initial target
        controlsRef.current.update();
      }
      if (onEntryFinish) onEntryFinish();
      return;
    }

    if (isTouring) {
      const nextIndex = tourIndex + 1;
      if (nextIndex < tourStops.length) {
        setTourIndex(nextIndex);
        setSelectedDistrict(tourStops[nextIndex]);
      } else {
        setIsTouring(false);
        setIsAnimating(false);
        setSelectedDistrict(null);
        resetIdleTimer();
        if (controlsRef.current) {
          controlsRef.current.target.set(0, 5, 0);
          controlsRef.current.update();
        }
      }
      return;
    }

    setIsAnimating(false);
    if (selectedDistrict) {
      setShowContentPanel(true);
      if (controlsRef.current && selectedDistrict.cameraFocus) {
        const { lookAt } = selectedDistrict.cameraFocus;
        controlsRef.current.target.set(lookAt[0], lookAt[1], lookAt[2]);
        controlsRef.current.update();
      }
    } else if (pov === 'main' && !isCalibrationMode) {
      resetIdleTimer();
      if (controlsRef.current) {
        controlsRef.current.target.set(0, 5, 0);
        controlsRef.current.update();
      }
    }
  }, [isEntering, isTouring, tourIndex, tourStops, selectedDistrict, pov, isCalibrationMode, resetIdleTimer, onEntryFinish]);

  const handleClosePanel = useCallback(() => {
    setShowContentPanel(false);
    setInfoPanelItem(null);
    setSelectedDistrict(null);
    setIsAnimating(true);
    audio.play('panel_close');
  }, [audio]);

  const handleToggleNavMenu = useCallback(() => setIsNavMenuOpen(prev => {
    if (!prev) audio.play('panel_open'); else audio.play('panel_close');
    return !prev;
  }), [audio]);

  const handleToggleHints = useCallback(() => setIsHintsOpen(prev => {
    if (!prev) audio.play('panel_open'); else audio.play('panel_close');
    return !prev;
  }), [audio]);

  const handleSetPov = useCallback((newPov: 'main' | 'ship') => {
    if (newPov === 'ship' && shipRefs.length > 0) {
      audio.play('confirm');
      const currentShipIndex = shipRefs.findIndex(ref => ref.current === targetShipRef?.current);
      const nextShipIndex = (currentShipIndex + 1) % shipRefs.length;
      setTargetShipRef(shipRefs[nextShipIndex]);
      setPov('ship');
      setSelectedDistrict(null);
      setIsAnimating(true);
    } else {
      setPov('main');
      setTargetShipRef(null);
      if (pov === 'ship') {
        setSelectedDistrict(null);
        setIsAnimating(true);
      }
    }
  }, [shipRefs, targetShipRef, pov, audio]);

  const handleToggleShipControl = useCallback(() => {
    if (shipControlMode === 'follow') {
      if (targetShipRef?.current) {
        audio.play('pilot_engage');
        audio.playLoop('engine_hum', { volume: 0.1 });
        const shipIndex = shipRefs.findIndex(ref => ref.current === targetShipRef.current);
        setControlledShipId(shipsData[shipIndex].id);
        setShipControlMode('manual');
        if (controlsRef.current) controlsRef.current.enabled = false;
      }
    } else {
      audio.play('pilot_disengage');
      audio.stop('engine_hum');
      setShipControlMode('follow');
      setControlledShipId(null);
    }
  }, [shipControlMode, targetShipRef, shipRefs, audio]);

  const handleFire = useCallback(() => {
    audio.play('laser');
    setFireRequest(prev => prev + 1)
  }, [audio]);

  const handleCanvasPointerDown = (e: React.PointerEvent) => {
    handleInteractionStart();
    if (shipControlMode === 'manual' && e.button === 0) handleFire();
  };

  const hudContext = useMemo(() => {
    if (shipControlMode === 'manual') return 'shipManual';
    if (pov === 'ship') return 'shipFollow';
    return 'overview';
  }, [shipControlMode, pov]);

  return (
    <>
      <Canvas
        shadows
        // PERFORMANCE FIX: Limit pixel ratio to 1.5 to prevent lag on Retina/4K displays
        dpr={[1, 1.5]}
        camera={{ position: OVERVIEW_CAMERA_POSITION, fov: 50, near: 1, far: 1000 }}
        onPointerDown={handleCanvasPointerDown}
        onPointerUp={handleInteractionEnd}
        onWheel={handleInteractionStart}
      >
        <Suspense fallback={null}>
            <SceneContent
              districts={districts}
              selectedDistrict={selectedDistrict}
              handleDistrictSelect={handleDistrictSelect}
              isCalibrationMode={isCalibrationMode}
              heldDistrictId={heldDistrictId}
              setHeldDistrictId={setHeldDistrictId}
              setShipRefs={setShipRefs}
              isPaused={isPaused}
              controlledShipId={controlledShipId}
              shipInputs={shipInputs}
              fireRequest={fireRequest}
            />
            {/* Preload all assets to prevent popping when animation starts */}
            <Preload all />
        </Suspense>

        {isCalibrationMode && <CalibrationGrid size={250} />}
        {heldDistrictId && (
            <BuildModeController
                districts={districts}
                setDistricts={setDistricts}
                heldDistrictId={heldDistrictId}
                onPlaceDistrict={() => setHeldDistrictId(null)}
                gridSize={250}
                gridDivisions={25}
            />
        )}

        <CameraRig 
          selectedDistrict={selectedDistrict} 
          onAnimationFinish={onAnimationFinish} 
          isAnimating={isAnimating} 
          pov={pov}
          targetShipRef={targetShipRef}
          isCalibrationMode={isCalibrationMode}
          isEntering={isEntering}
          isWaitingToStart={isWaitingToStart} 
        />

        <OrbitControls
          ref={controlsRef}
          enableDamping
          dampingFactor={0.1}
          autoRotate={isAutoRotating}
          autoRotateSpeed={0.2}
          minDistance={15}
          maxDistance={300}
          maxPolarAngle={Math.PI / 2.1}
          enablePan={!isCalibrationMode}
          target={[0, 5, 0]}
          onChange={handleControlsChange}
          enabled={!isAnimating && !isEntering && !isWaitingToStart && pov !== 'ship'}
        />

        <EffectComposer>
          {/* PERFORMANCE FIX: Removed Noise effect which is expensive on low-power devices/Opera */}
          {/* <Noise premultiply blendFunction={BlendFunction.ADD} opacity={0.05} /> */}
          <Bloom luminanceThreshold={1.2} intensity={0.6} levels={8} mipmapBlur />
        </EffectComposer>

        {infoPanelItem && <HolographicInfoPanel district={infoPanelItem} onClose={() => setInfoPanelItem(null)} />}

      </Canvas>
      {showInitialHint && <InitialHintTooltip />}
      <div
        className={`hud-container ${isHudVisible ? 'visible' : ''}`}
        style={{ pointerEvents: isHudVisible ? 'auto' : 'none' }}
      >
        <HUD 
          selectedDistrict={selectedDistrict}
          onToggleNavMenu={handleToggleNavMenu}
          onToggleHints={handleToggleHints}
          pov={pov}
          onSetPov={handleSetPov}
          onGoHome={handleGoHome}
          isCalibrationMode={isCalibrationMode}
          heldDistrictId={heldDistrictId}
          shipControlMode={shipControlMode}
          onToggleShipControl={handleToggleShipControl}
          onFire={handleFire}
          isTouchDevice={isTouchDevice}
          onShipTouchInputChange={setShipTouchInputs}
          isAnyPanelOpen={isAnyPanelOpen}
        />
        <QuickNavMenu 
          isOpen={isNavMenuOpen}
          onClose={handleToggleNavMenu}
          onSelectDistrict={(d) => {
            handleDistrictSelect(d);
            setIsNavMenuOpen(false);
          }}
          districts={navDistricts}
        />
        <ProjectSelectionPanel
          isOpen={showContentPanel}
          district={selectedDistrict}
          onClose={handleClosePanel}
        />
        <HintsPanel
          isOpen={isHintsOpen}
          onClose={handleToggleHints}
          context={hudContext}
        />
        <ExportLayoutModal
            isOpen={isExportModalOpen}
            onClose={() => { /* setIsExportModalOpen(false) */ }}
            jsonData={exportedLayoutJson}
        />
      </div>
    </>
  );
};

import React, { useMemo, useCallback } from 'react';
import { useThree, useFrame, ThreeEvent } from '@react-three/fiber';
import * as THREE from 'three';
import { CityDistrict } from '../../types';

interface BuildModeControllerProps {
    districts: CityDistrict[];
    setDistricts: React.Dispatch<React.SetStateAction<CityDistrict[]>>;
    heldDistrictId: string | null;
    onPlaceDistrict: () => void;
    gridSize: number;
    gridDivisions: number;
}

const GRID_Y_POSITION = -3; // Must match the visual grid's Y position

export const BuildModeController: React.FC<BuildModeControllerProps> = ({
    setDistricts,
    heldDistrictId,
    onPlaceDistrict,
    gridSize,
    gridDivisions
}) => {
    const { camera, raycaster, mouse } = useThree();

    // An invisible plane for raycasting mouse position in the 3D world
    const groundPlane = useMemo(() => new THREE.Plane(new THREE.Vector3(0, 1, 0), -(GRID_Y_POSITION + 5)), []);

    const intersectionPoint = useMemo(() => new THREE.Vector3(), []);

    const cellSize = useMemo(() => gridSize / gridDivisions, [gridSize, gridDivisions]);
    const halfGridSize = useMemo(() => gridSize / 2, [gridSize]);

    const snapToGrid = useCallback((point: THREE.Vector3) => {
        // Clamp the position to within the grid boundaries
        const clampedX = THREE.MathUtils.clamp(point.x, -halfGridSize, halfGridSize);
        const clampedZ = THREE.MathUtils.clamp(point.z, -halfGridSize, halfGridSize);

        // Snap to the nearest cell center
        const snappedX = Math.round(clampedX / cellSize) * cellSize;
        const snappedZ = Math.round(clampedZ / cellSize) * cellSize;

        return new THREE.Vector3(snappedX, 0, snappedZ); // Y will be the district's original Y
    }, [cellSize, halfGridSize]);

    useFrame(() => {
        if (!heldDistrictId) return;

        raycaster.setFromCamera(mouse, camera);
        if (raycaster.ray.intersectPlane(groundPlane, intersectionPoint)) {
            const snappedPosition = snapToGrid(intersectionPoint);

            setDistricts(prevDistricts =>
                prevDistricts.map(d => {
                    if (d.id === heldDistrictId) {
                        // Keep original height, but update X and Z
                        return { ...d, position: [snappedPosition.x, d.position[1], snappedPosition.z], isDirty: true };
                    }
                    return d;
                })
            );
        }
    });

    const handlePlace = (e: ThreeEvent<PointerEvent>) => {
        e.stopPropagation();
        if (heldDistrictId) {
            onPlaceDistrict();
        }
    }

    return (
        // This mesh acts as the invisible interactive floor for placing objects
        <mesh 
            visible={false} 
            rotation={[-Math.PI / 2, 0, 0]} 
            position={[0, GRID_Y_POSITION, 0]}
            onPointerDown={handlePlace}
        >
            <planeGeometry args={[gridSize, gridSize]} />
            <meshBasicMaterial />
        </mesh>
    );
};

import React from 'react';
import { Grid } from '@react-three/drei';
import * as THREE from 'three';
import { useThree } from '@react-three/fiber';

interface CalibrationGridProps {
  size?: number;
}

const GRID_COLOR = '#00ffff'; // Cyan
const FADE_DISTANCE = 50;
const GRID_Y_POSITION = -3; // Positioned just above the terrain base

export const CalibrationGrid: React.FC<CalibrationGridProps> = ({ size = 250 }) => {
  // Call useThree hook to ensure R3F types are loaded for JSX.
  useThree();
  const divisions = 25;

  const gridConfig = {
    cellSize: size / divisions,
    cellThickness: 1,
    cellColor: new THREE.Color(GRID_COLOR).setScalar(0.2),
    sectionSize: size / divisions * 5, // Make major lines every 5 cells
    sectionThickness: 1.5,
    sectionColor: new THREE.Color(GRID_COLOR).setScalar(0.5),
    fadeDistance: FADE_DISTANCE,
    fadeStrength: 1,
    followCamera: false,
    infiniteGrid: false,
  };

  return (
    <group>
        <Grid position={[0, GRID_Y_POSITION, 0]} args={[size, size]} {...gridConfig} />
    </group>
  );
};

import React, { useLayoutEffect, useMemo, useRef } from 'react';
import { useGLTF } from '@react-three/drei';
import * as THREE from 'three';
import { useFrame, useThree } from '@react-three/fiber';

export const CityModel: React.FC = React.memo(() => {
  // FIX: Call useThree to provide types for JSX primitives
  useThree();
  const { scene } = useGLTF('https://raw.githubusercontent.com/wiwitmikael-a11y/3Dmodels/main/cyberpunk_city.glb');

  const clonedScene = useMemo(() => scene.clone(), [scene]);
  const emissiveMaterials = useRef<THREE.MeshStandardMaterial[]>([]);

  useLayoutEffect(() => {
    const materials: THREE.MeshStandardMaterial[] = [];
    // --- FIX: Cache for cloned materials to prevent cross-contamination ---
    // This ensures that modifying the city's materials doesn't affect other models
    // that might share materials from the cache (like the DeLorean).
    const materialCache: { [uuid: string]: THREE.Material } = {};

    clonedScene.traverse((child) => {
      if (child instanceof THREE.Mesh) {
        child.castShadow = true;
        child.receiveShadow = true;
        if (child.material instanceof THREE.MeshStandardMaterial) {

          // --- FIX: Clone material if we haven't already ---
          if (!materialCache[child.material.uuid]) {
              materialCache[child.material.uuid] = child.material.clone();
          }
          child.material = materialCache[child.material.uuid] as THREE.MeshStandardMaterial;

          // Now, modify the unique, cloned material
          child.material.metalness = 0.7;
          child.material.roughness = 0.4;

          // Aktifkan emisi pada material tertentu untuk cahaya kota
          if (child.material.name.includes('light') || child.material.name.includes('emissive')) {
            child.material.emissive = child.material.color;
            child.material.emissiveIntensity = 2;
            materials.push(child.material);
          }
        }
      }
    });
    emissiveMaterials.current = materials;
  }, [clonedScene]);

  useFrame(({ clock }) => {
    const pulse = Math.sin(clock.getElapsedTime() * 2) * 0.5 + 0.5; // Varies between 0 and 1
    emissiveMaterials.current.forEach(material => {
      // Modulate intensity for a living city effect
      material.emissiveIntensity = 1.5 + pulse * 2;
    });
  });

  return <primitive object={clonedScene} position={[0, -5, 0]} scale={15} />;
});

