export const ProjectDisplay: React.FC<ProjectDisplayProps> = ({ item, isLocked, onClick }) => {
  // FIX: Call useThree to provide types for JSX primitives
  useThree();
  const groupRef = useRef<THREE.Group>(null!);
  const [isHovered, setIsHovered] = useState(false);
  const [isVisible, setIsVisible] = useState(false);
  const [showDeniedMsg, setShowDeniedMsg] = useState(false);

  useEffect(() => {
    const timer = setTimeout(() => setIsVisible(true), Math.random() * 400 + 100);
    return () => clearTimeout(timer);
  }, []);

  useFrame((_, delta) => {
    if (!groupRef.current) return;

    const targetScale = isVisible ? (isHovered && !isLocked ? 1.1 : 1) : 0;
    groupRef.current.scale.lerp(new THREE.Vector3(targetScale, targetScale, targetScale), delta * 8);
  });

  const handleClick = (e: ThreeEvent<MouseEvent>) => {
    e.stopPropagation();
    if (isLocked) {
        setShowDeniedMsg(true);
        setTimeout(() => setShowDeniedMsg(false), 2000);
    } else {
        onClick();
    }
  };

  const handlePointerOver = (e: ThreeEvent<PointerEvent>) => {
    e.stopPropagation();
    setIsHovered(true);
    if (!isLocked) document.body.style.cursor = 'pointer';
  };

  const handlePointerOut = (e: ThreeEvent<PointerEvent>) => {
    e.stopPropagation();
    setIsHovered(false);
    document.body.style.cursor = 'auto';
  };

  const baseOpacity = isLocked ? 0.3 : 0.8;
  const imageOpacity = isLocked ? 0.2 : (isHovered ? 1 : 0.9);

  return (
    <group
      ref={groupRef}
      position={item.position}
      onClick={handleClick}
      onPointerOver={handlePointerOver}
      onPointerOut={handlePointerOut}
      scale={0}
    >
      <RoundedBox args={[6, 8.5, 0.2]} radius={0.1}>
        <meshStandardMaterial 
          color="#051020" 
          roughness={0.2} 
          metalness={0.5} 
          transparent 
          opacity={baseOpacity} 
          emissive={isHovered && !isLocked ? '#00ffff' : '#000000'}
          emissiveIntensity={0.5}
        />
      </RoundedBox>

      {item.imageUrl && (
        <Image
          url={item.imageUrl}
          scale={[5.5, 4]}
          position={[0, 2, 0.15]}
          grayscale={isLocked ? 1 : 0}
        >
          <meshStandardMaterial 
            transparent 
            opacity={imageOpacity} 
            emissive={"#ffffff"} 
            emissiveIntensity={isHovered && !isLocked ? 0.2 : 0} 
            toneMapped={false} 
          />
        </Image>
      )}
      {isLocked && <LockIcon />}
      {showDeniedMsg && <AccessDeniedMessage />}

      <Text
        position={[0, -1.5, 0.15]}
        fontSize={0.35}
        color={isLocked ? "#555" : "white"}
        anchorX="center"
        anchorY="top"
        maxWidth={5}
        textAlign="center"
      >
        {item.title}
      </Text>
      <Text
        position={[0, -2.2, 0.15]}
        fontSize={0.25}
        color={isLocked ? "#444" : "#aaa"}
        anchorX="center"
        anchorY="top"
        maxWidth={5}
        textAlign="center"
        lineHeight={1.3}
      >
        {item.description}
      </Text>
    </group>
  );
};

import React, { useRef } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import * as THREE from 'three';
import { createNoise2D } from 'simplex-noise';

const noise2D = createNoise2D();

interface ThrustTrailProps {
    width?: number;
    length?: number;
    opacity?: number;
    color?: string;
    position?: [number, number, number];
}

export const ThrustTrail: React.FC<ThrustTrailProps> = ({ width = 0.3, length = 3, opacity = 0.5, color = '#00ffff', position = [0, 0, 0] }) => {
    // FIX: Call useThree to provide types for JSX primitives
    useThree();
    const meshRef = useRef<THREE.Mesh>(null!);

    // This component renders a cone pointing towards -Z (backwards).
    // We offset it by half its length so its base starts at the provided `position`.
    const trailPosition: [number, number, number] = [position[0], position[1], position[2] - length / 2];

    useFrame(({ clock }) => {
        if (meshRef.current) {
            const time = clock.getElapsedTime();
            const material = meshRef.current.material as THREE.MeshStandardMaterial;

            // Use noise to create a more chaotic, fiery flicker effect
            const baseFrequency = 15;

            // Flicker both length and width slightly differently and chaotically
            const lengthFlicker = 1.0 + (noise2D(time * baseFrequency, 0) + 1) / 2 * 0.3; // Range [1.0, 1.3]
            const widthFlicker = 1.0 + (noise2D(0, time * (baseFrequency + 2)) + 1) / 2 * 0.2; // Range [1.0, 1.2]

            // Y-axis on the mesh corresponds to the cone's height/length
            meshRef.current.scale.set(widthFlicker, lengthFlicker, widthFlicker);

            // Flicker opacity for a more dynamic feel
            material.opacity = opacity * (0.7 + (noise2D(time * 5, time * 5) + 1) / 2 * 0.3); // Range [0.7, 1.0] * base opacity
        }
    });

    return (
        <mesh ref={meshRef} position={trailPosition} rotation-x={Math.PI / 2}>
            <coneGeometry args={[width, length, 8]} />
            <meshStandardMaterial
                color={color}
                emissive={color}
                emissiveIntensity={4}
                transparent
                opacity={opacity}
                blending={THREE.AdditiveBlending}
                depthWrite={false}
                toneMapped={false}
            />
        </mesh>
    );
};

import React, { useMemo, useRef, useLayoutEffect } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import * as THREE from 'three';

const BLOCK_COUNT = 150;
const MIN_RADIUS = 200; // Far outside the main districts (approx 100-120 range)
const MAX_RADIUS = 450;
const COLOR_PALETTE = ['#00aaff', '#00ffff', '#0055aa'];

export const BackgroundArchitecture: React.FC = React.memo(() => {
  useThree();
  const meshRef = useRef<THREE.InstancedMesh>(null!);
  const dummy = useMemo(() => new THREE.Object3D(), []);

  // Store random data for each block to use in animation
  const particles = useMemo(() => {
    return new Array(BLOCK_COUNT).fill(0).map(() => ({
      speed: Math.random() * 0.2 + 0.1,
      offset: Math.random() * 100,
      baseY: Math.random() * 50 - 20, // Some below ground, some floating high
      x: 0,
      z: 0,
      height: 0,
    }));
  }, []);

  useLayoutEffect(() => {
    if (!meshRef.current) return;

    for (let i = 0; i < BLOCK_COUNT; i++) {
      // Polar coordinates for distribution ring
      // Use Math.sqrt(Math.random()) for uniform distribution in a ring
      const r = Math.sqrt(Math.random()) * (MAX_RADIUS - MIN_RADIUS) + MIN_RADIUS;
      const theta = Math.random() * 2 * Math.PI;

      const x = r * Math.cos(theta);
      const z = r * Math.sin(theta);

      particles[i].x = x;
      particles[i].z = z;

      // Randomize Scale
      const width = Math.random() * 20 + 10;
      const depth = Math.random() * 20 + 10;
      const height = Math.random() * 120 + 30; // Tall skyscraper-like blocks
      particles[i].height = height;

      dummy.position.set(x, particles[i].baseY + height / 2, z);
      dummy.scale.set(width, height, depth);
      dummy.rotation.y = Math.random() * Math.PI; // Random rotation

      dummy.updateMatrix();
      meshRef.current.setMatrixAt(i, dummy.matrix);

      // Randomize color slightly for each instance
      const color = new THREE.Color(COLOR_PALETTE[Math.floor(Math.random() * COLOR_PALETTE.length)]);
      meshRef.current.setColorAt(i, color);
    }
    meshRef.current.instanceMatrix.needsUpdate = true;
    if (meshRef.current.instanceColor) meshRef.current.instanceColor.needsUpdate = true;
  }, [dummy, particles]);

  useFrame(({ clock }) => {
    if (!meshRef.current) return;

    const time = clock.getElapsedTime();

    for (let i = 0; i < BLOCK_COUNT; i++) {
        const p = particles[i];

        // Gentle floating animation
        // Using a sine wave based on time, unique speed, and random offset
        const floatingY = Math.sin(time * p.speed + p.offset) * 10;

        // Retrieve current transform (we only want to update Y position)
        meshRef.current.getMatrixAt(i, dummy.matrix);
        dummy.matrix.decompose(dummy.position, dummy.quaternion, dummy.scale);

        dummy.position.y = p.baseY + p.height / 2 + floatingY;

        dummy.updateMatrix();
        meshRef.current.setMatrixAt(i, dummy.matrix);
    }
    meshRef.current.instanceMatrix.needsUpdate = true;
  });

  return (
    <instancedMesh ref={meshRef} args={[undefined, undefined, BLOCK_COUNT]}>
      <boxGeometry args={[1, 1, 1]} /> {/* Base geometry 1x1x1, scaled via matrix */}
      <meshStandardMaterial
        color="#00aaff"
        transparent
        opacity={0.15} // Very transparent
        metalness={0.8}
        roughness={0.1}
        depthWrite={false} // Prevents z-fighting artifacts with transparency
        blending={THREE.AdditiveBlending} // Adds a nice holographic glow effect
      />
    </instancedMesh>
  );
});

import React, { Suspense, useLayoutEffect, useMemo, useRef, useCallback, useState } from 'react';
import { useGLTF, Text, RoundedBox } from '@react-three/drei';
