import { HolographicProjector } from './HolographicProjector';

interface InteractiveModelProps {
  district: CityDistrict;
  isSelected: boolean;
  onSelect: (district: CityDistrict) => void;
  isCalibrationMode: boolean;
  isHeld: boolean;
  onSetHeld: (id: string | null) => void;
}

interface ModelProps {
  url: string;
  scale: number;
  isHeld: boolean;
  onPointerDown: (e: ThreeEvent<PointerEvent>) => void;
  onPointerUp: (e: ThreeEvent<PointerEvent>) => void;
  onPointerOver: (e: ThreeEvent<PointerEvent>) => void;
  onPointerOut: (e: ThreeEvent<PointerEvent>) => void;
}

// Robust Error Boundary specifically for model loading
class ModelErrorBoundary extends React.Component<{ fallback: React.ReactNode, children?: React.ReactNode }, { hasError: boolean }> {
  public state: { hasError: boolean } = { hasError: false };
  public readonly props: { fallback: React.ReactNode, children?: React.ReactNode };

  constructor(props: { fallback: React.ReactNode, children?: React.ReactNode }) {
    super(props);
    this.props = props;
  }
  static getDerivedStateFromError(_error: any) {
    return { hasError: true };
  }
  componentDidCatch(error: any, _info: any) {
    console.error("3D Model load error (handled silently):", error);
  }
  render() {
    if (this.state.hasError) {
      return this.props.fallback;
    }
    return this.props.children;
  }
}

function Model({ url, scale, isHeld, onPointerOver, onPointerOut, onPointerDown, onPointerUp }: ModelProps) {
  // FIX: Call useThree to provide types for JSX primitives
  useThree();
  const { scene } = useGLTF(url);
  const clonedScene = useMemo(() => scene.clone(), [scene]);
  const originalMaterials = useRef<Map<string, THREE.Material>>(new Map());
  const hoverColor = useMemo(() => new THREE.Color('#00ffff'), []); // Cyan glow on hover
  const heldColor = useMemo(() => new THREE.Color('#ffaa00'), []); // Orange glow on hold

  // --- AUTO-GLOW LOGIC ---
  // This effect scans the loaded model. If a material has a bright color (neon),
  // it automatically turns on emission so it glows in the city.
  useLayoutEffect(() => {
    clonedScene.traverse((child: any) => {
      if (child.isMesh) {
        child.castShadow = true;
        child.receiveShadow = true;

        if (child.material) {
            // Save original for reset
            originalMaterials.current.set(child.uuid, child.material.clone());

            // Check if material is standard (supports emission)
            if (child.material instanceof THREE.MeshStandardMaterial) {
                const color = child.material.color;
                // Calculate brightness (simple luminance approximation)
                const brightness = (color.r * 0.299 + color.g * 0.587 + color.b * 0.114);

                // If the texture color is bright/neon (brightness > 0.5), make it glow!
                if (brightness > 0.4) {
                    child.material.emissive = color.clone();
                    child.material.emissiveIntensity = 1.5; // Base glow intensity
                    child.material.toneMapped = false; // Enhance bloom effect
                } else {
                    // Make dark parts darker/metallic for contrast
                    child.material.metalness = 0.8;
                    child.material.roughness = 0.2;
                }
            }
        }
      }
    });
  }, [clonedScene]);

  const applyHighlight = useCallback((color: THREE.Color, intensity: number) => {
    clonedScene.traverse((child: any) => {
        if (child.isMesh && child.material instanceof THREE.MeshStandardMaterial) {
            // We overlay the highlight color on top of existing emission
            child.material.emissive.lerp(color, 0.6); 
            child.material.emissiveIntensity = intensity;
        }
    });
  }, [clonedScene]);

  const resetMaterials = useCallback(() => {
      clonedScene.traverse((child: any) => {
        if (child.isMesh && originalMaterials.current.has(child.uuid)) {
            const original = originalMaterials.current.get(child.uuid) as THREE.MeshStandardMaterial;
            if (child.material instanceof THREE.MeshStandardMaterial) {
                // Revert to the "Auto-Glow" state we set up in useLayoutEffect
                // Re-calculate basic auto-glow restoration
                const color = original.color;
                const brightness = (color.r * 0.299 + color.g * 0.587 + color.b * 0.114);

                child.material.color.copy(original.color);

                if (brightness > 0.4) {
                    child.material.emissive.copy(original.color);
                    child.material.emissiveIntensity = 1.5; 
                } else {
                    child.material.emissive.setHex(0x000000);
                    child.material.emissiveIntensity = 0;
                }
            }
        }
    });
  }, [clonedScene]);

  const handlePointerOver = (e: ThreeEvent<PointerEvent>) => {
    onPointerOver(e);
    if (!isHeld) applyHighlight(hoverColor, 2.0);
  };

  const handlePointerOut = (e: ThreeEvent<PointerEvent>) => {
    onPointerOut(e);
    if (!isHeld) resetMaterials();
  };

  useFrame((state, delta) => {
      // Gentle floating animation for the whole district
      // Using unique offset based on model ID logic or random if not available
      const time = state.clock.getElapsedTime();
      clonedScene.position.y = Math.sin(time * 0.5) * 1.5; 

      if(isHeld) {
        applyHighlight(heldColor, 2.5);
      } else {
         const isHovered = (document.body.style.cursor === 'pointer' || document.body.style.cursor === 'grab');
         if(!isHovered) {
             // Optional: pulsating glow for the district
             clonedScene.traverse((child: any) => {
                 if (child.isMesh && child.material.emissiveIntensity > 0) {
                     // Pulse between 1.2 and 1.8
                     child.material.emissiveIntensity = 1.5 + Math.sin(time * 2) * 0.3;
                 }
             });
         }
      }
  });

  return (
    <group>
        {/* 
           Invisible Hitbox to capture clicks around the model 
        */}
        <mesh 
            position={[0, 15, 0]} 
            scale={scale * 1.2} 
            onPointerOver={handlePointerOver}
            onPointerOut={handlePointerOut}
            onPointerDown={onPointerDown}
            onPointerUp={onPointerUp}
        >
            <cylinderGeometry args={[25, 25, 40, 8]} /> 
            <meshBasicMaterial transparent opacity={0} depthWrite={false} />
        </mesh>

        <primitive
            object={clonedScene}
            scale={scale}
            // Keep events on the actual model mesh as well for precision
            onPointerOver={handlePointerOver}
            onPointerOut={handlePointerOut}
            onPointerDown={onPointerDown}
            onPointerUp={onPointerUp}
        />
    </group>
  );
}

export const InteractiveModel: React.FC<InteractiveModelProps> = ({ district, isSelected, onSelect, isCalibrationMode, isHeld, onSetHeld }) => {
  useThree();
  const groupRef = useRef<THREE.Group>(null!);
  const audio = useAudio();

  const [holdProgress, setHoldProgress] = useState(0);
  const isHoldingRef = useRef(false);
  const animationFrameRef = useRef<number | null>(null);
  const actionTriggeredRef = useRef(false);

  // FIX: Reduced hold duration for snappier interaction
  const HOLD_DURATION = 400; // 400ms

  const cancelHold = useCallback(() => {
    isHoldingRef.current = false;
    if (animationFrameRef.current) {
        cancelAnimationFrame(animationFrameRef.current);
    }
    setHoldProgress(0);
    actionTriggeredRef.current = false;
    audio.stop('district_hold');
  }, [audio]);

  const handlePointerOver = useCallback((e: ThreeEvent<PointerEvent>) => {
    e.stopPropagation();
    audio.play('district_hover', { volume: 0.4, rate: 0.8 });
    if (isCalibrationMode) document.body.style.cursor = 'grab';
    else document.body.style.cursor = 'pointer';
  }, [isCalibrationMode, audio]);

  const handlePointerOut = useCallback((e: ThreeEvent<PointerEvent>) => {
    e.stopPropagation();
    cancelHold();
    document.body.style.cursor = 'auto';
  }, [cancelHold]);

  const handlePointerDown = useCallback((e: ThreeEvent<PointerEvent>) => {
    e.stopPropagation();

    if (isCalibrationMode) {
      onSetHeld(district.id);
      return;
    }

    audio.playHoldSound('district_hold', { volume: 0.4 });
    isHoldingRef.current = true;
    actionTriggeredRef.current = false;
    const startTime = performance.now();

    const animateHold = (currentTime: number) => {
        if (!isHoldingRef.current) {
            cancelHold();
            return;
        }

        const elapsedTime = currentTime - startTime;
        const progress = Math.min(elapsedTime / HOLD_DURATION, 1);
        setHoldProgress(progress);

        // Trigger slightly before full completion for better feel
        if (progress >= 0.9 && !actionTriggeredRef.current) {
            actionTriggeredRef.current = true;
            onSelect(district);
        }

        if (progress >= 1) {
            cancelHold();
        } else {
            animationFrameRef.current = requestAnimationFrame(animateHold);
        }
    };

    animationFrameRef.current = requestAnimationFrame(animateHold);
  }, [isCalibrationMode, onSetHeld, district, onSelect, audio, cancelHold]);

  const handlePointerUp = useCallback((e: ThreeEvent<PointerEvent>) => {
    e.stopPropagation();
    cancelHold();
  }, [cancelHold]);

  return (
    <group ref={groupRef} position={district.position}>
      <ModelErrorBoundary fallback={<HolographicProjector position={[0, -5, 0]} />}>
        <Suspense fallback={<HolographicProjector position={[0, -5, 0]} />}>
            <Model 
            url={district.modelUrl!}
            scale={district.modelScale || 1}
            isHeld={isHeld}
            onPointerOver={handlePointerOver}
            onPointerOut={handlePointerOut}
            onPointerDown={handlePointerDown}
            onPointerUp={handlePointerUp}
            />
        </Suspense>
      </ModelErrorBoundary>

      <HolographicDistrictLabel 
        district={district}
        isSelected={isSelected}
        onSelect={onSelect}
        isCalibrationMode={isCalibrationMode}
        isHeld={isHeld}
        onSetHeld={onSetHeld}
        pointerEventsEnabled={true} 
      />

      {holdProgress > 0 && !isCalibrationMode && (
        <group position={[0, 15, 0]}>
            <Text
                position={[0, 10, 0]} 
                fontSize={3}
                color="white"
                anchorX="center"
                anchorY="middle"
            >
                HOLD
                <meshStandardMaterial emissive={'white'} emissiveIntensity={2} toneMapped={false} />
            </Text>
            {/* Gauge Background */}
            <RoundedBox args={[28, 1.5, 0.2]} radius={0.5} position={[0, 7.5, 0]}>
                <meshStandardMaterial color="#000000" transparent opacity={0.5} />
            </RoundedBox>
            {/* Gauge Fill */}
            <RoundedBox
                args={[28, 1.5, 0.2]}
                radius={0.5}
                position={[-14 * (1 - holdProgress), 7.5, 0.1]}
                scale={[holdProgress, 1, 1]}
            >
                <meshStandardMaterial color="#ff9900" emissive="#ff9900" emissiveIntensity={2} toneMapped={false} />
            </RoundedBox>
        </group>
      )}
    </group>
  );
};

